options.css:
:root{
  /* ===== MT THEME (standard dark blue / industrial) ===== */
  --mt-accent: #58a6ff;
  --mt-accent2:#7dc4ff;

  --mt-ok:#22c55e;
  --mt-bad:#ff5c5c;
  --mt-warn:#f6c445;

  --mt-text:#eaf3ff;

  --mt-panel-border: rgba(88,166,255,0.22);
  --mt-panel-topglow: rgba(10,20,36,0.92);
  --mt-panel-bg1: rgba(18,36,60,0.88);
  --mt-panel-bg2: rgba(10,20,36,0.92);
  --mt-soft-line: rgba(255,255,255,0.08);
  --mt-card-bg: rgba(10,20,36,0.92);
  --mt-input-bg: rgba(10,18,30,0.82);
}

/* ================== LAYOUT (same as ct-layout) ================== */
.mt-layout{
  height:100%;
  display:grid;
  grid-template-columns: 2.05fr 1fr;
  gap: 12px;
  font-family:"Segoe UI",system-ui,sans-serif;
  color: var(--mt-text);
}


.kpi-main,
.readout-main{
  font-weight: 900;
  letter-spacing: 0.5px;
}

/* shared panel look */
.panel{
  border-radius: 14px;
  border: 1px solid var(--mt-panel-border);
  background: linear-gradient(180deg, var(--mt-panel-bg1), var(--mt-panel-bg2)),
            radial-gradient(circle at top, rgba(88,166,255,0.05), transparent 70%);
  box-shadow: 0 12px 26px rgba(0, 0, 0, 0.45), inset 0 0 0 1px rgba(125,196,255,0.05);
  padding: 12px;
  overflow:hidden;
  position: relative;
}
.panel:before{
  content:"";
  position:absolute;
  left:10px; right:10px; top:0;
  height:2px;
  background: linear-gradient(90deg, transparent, var(--mt-panel-topglow), transparent);
  opacity:0.75;
}

.mt-left{ height:100%; }
.mt-right{ height:100%; display:flex; flex-direction:column; gap: 12px; }

/* ================== HEADER ================== */
.mt-detail-header{
  display:flex;
  justify-content:space-between;
  align-items:center;
  margin-bottom:10px;
}
.mt-detail-title{
  font-size: 26px;
  font-weight: 900;
  letter-spacing: 1.6px;
  text-transform: uppercase;
  text-shadow: 0 0 12px rgba(88,166,255,0.18);

}

.mt-detail-chip{
  display:flex; align-items:center; gap:10px;
  padding:8px 12px;
  border-radius: 12px;
  border: 1px solid rgba(88,166,255,0.26);
  background: linear-gradient(180deg, rgba(18,32,52,0.92), rgba(9,16,28,0.92));
}
.chip-label{ font-weight:900; opacity:0.85; letter-spacing:1px; font-size:12px; color:#d8e8ff; }
.chip-value{
  font-weight:900; font-size:16px;
  padding:4px 10px;
  border-radius: 999px;
  background: rgba(88,166,255,0.14);
  border: 1px solid rgba(88,166,255,0.30);
  color: #ffffff;
}

/* ================== GRID (left side panels) ================== */
.mt-detail-grid{
  display:grid;
  grid-template-columns: 1fr 1fr;
  gap: 12px;
  height: calc(100% - 58px);
}

.panel-title{
  font-weight: 900;
  letter-spacing: 1px;
  text-transform: uppercase;
  font-size: 12px;
  opacity: 0.95;
  margin-bottom: 10px;
  color: #d9e9ff;
}

/* ================== Tank ================== */
.tank-panel{ display:flex; flex-direction:column; gap: 10px; height:100%; }

.tank-panel{
  position: relative;
  border-radius: 12px;
  background:
    radial-gradient(circle at 45% 25%, rgba(88,166,255,0.05), transparent 70%),
    linear-gradient(180deg, rgba(10,18,30,0.96), rgba(2,8,16,0.99));
}
.tank-hero{
  display:flex;
  justify-content: center;
  align-items:flex-start;
  padding-top: 4px;
  margin-bottom: -6px;
}

.tank-pack{
  display:flex;
  justify-content:center;
  align-items:flex-start;
  gap: 12px;
  margin: 0 auto;
}

.tank-scale.big{
  position:relative;
  height: 175px;
  width: 48px;
  font-size: 12px;
  color: rgb(210, 225, 245);
}
.tank-scale.big .tick{ position:absolute; left:0; }
.tank-scale.big .tick-top{ top:0; }
.tank-scale.big .tick-mid{ top:50%; transform:translateY(-50%); }
.tank-scale.big .tick-bottom{ bottom:0; }

.tank-body.big{ display:flex; flex-direction:column; align-items:center; }
.tank-outer.big{ position:relative; width: 135px; height: 195px; }

.tank-inner.big{
  position:absolute; left:0; right:0; top:0; bottom:16px;
  margin:auto;
  border-radius: 16px;
  border: 2px solid rgba(255,255,255,0.82);
  background: radial-gradient(circle at 30% 0%, #203553 0, #0f1d31 62%, #09111b 100%);
  overflow:hidden;
  box-shadow: 0 0 10px rgba(0,0,0,0.65), inset 0 0 14px rgba(0,0,0,0.85), 0 0 18px rgba(88,166,255,0.12);
}

.tank-glass{
  position:absolute; top:4%; bottom:45%; left:10%; width:20%;
  border-radius:50px;
  background: linear-gradient(to bottom, rgba(255,255,255,0.20), rgba(255,255,255,0));
}
.tank-band{
  position:absolute; left:0; right:0; bottom:24%;
  height:12%;
  background: rgba(88,166,255, 0.10);
}

.tank-fill{
  position:absolute; left:0; right:0; bottom:0;
  height:45%;
  background: linear-gradient(to top, #2d6cdf, #58a6ff 55%, #cfe7ff 100%);
  box-shadow: 0 0 14px rgba(88,166,255,0.35), inset 0 3px 10px rgba(255,255,255,0.16);
}
.tank-fill.level-green{ background: linear-gradient(to top, #118b43, #22c55e 45%, #bbf7d0 100%); }
.tank-fill.level-yellow{ background: linear-gradient(to top, #b88900, #f6c445 55%, #fff1b3 100%); }
.tank-fill.level-red{ background: linear-gradient(to top, #9f1f1f, #ff5c5c 50%, #ffd4d4 100%); }

.tank-foot{
  position:absolute; bottom:0;
  width:16px; height:10px;
  background: linear-gradient(to top, #62758d, #9aabbe);
  border-radius: 4px 4px 0 0;
  box-shadow: 0 0 6px rgba(0,0,0,0.65);
}
.tank-foot.left{ left: 16px; }
.tank-foot.right{ right: 16px; }

.tank-zone{
  position:absolute; left:12px;
  font-size: 10px; font-weight: 900;
  letter-spacing: 1px; opacity: 0.72;
  color:#edf5ff;
}
.tank-zone.top{ top: 10px; }
.tank-zone.mid{ top: 48%; transform: translateY(-50%); }
.tank-zone.low{ bottom: 24px; }

.tank-readout{ margin-top: 6px; text-align:center; }
.readout-main{
  font-size: 34px; font-weight: 900; letter-spacing: 0.6px;
  color:#ffffff;
}
.readout-unit{ font-size: 14px; font-weight: 900; opacity:0.85; margin-left:6px; color:#d8e8ff; }

/* last update */
.mt-last-update,
.ct-last-update{
  margin-top:10px;
  padding:6px 10px;
  border-radius:999px;
  border:1px solid rgba(88,166,255,.22);
  background: rgba(9,18,30,.70);
  font-size:11px;
  font-weight:900;
  letter-spacing:.8px;
  color:#d8e8ff;
}
.mt-last-update b,
.ct-last-update b{ color:#ffffff; margin-left:8px; }


.kpi-panel{ display:flex; flex-direction:column; height:100%; }
.kpi-panel{
  position: relative;
  border-radius: 12px;
  background:
    radial-gradient(circle at 45% 25%, rgba(88,166,255,0.05), transparent 70%),
    linear-gradient(180deg, rgba(10,18,30,0.96), rgba(2,8,16,0.99));
}

.kpi-grid{
  display:grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 10px;
  align-content:start;
}
.kpi-card{
  border-radius: 14px;
  border: 1px solid rgba(88,166,255,0.14);
  background: var(--mt-card-bg);
  padding: 10px;
  box-shadow: inset 0 0 0 1px rgba(125,196,255,0.04);
}
.kpi-label{
  font-size: 11px;
  font-weight: 900;
  text-transform: uppercase;
  letter-spacing: 1px;
  color:#d9e9ff;
}
.kpi-main{ margin-top: 6px; font-size: 24px; font-weight: 900; color:#ffffff; }
.kpi-unit{ font-size: 12px; font-weight: 900; opacity:0.8; margin-left:6px; color:#d9e9ff; }

.kpi-card.kpi-green{
  border: 1px solid rgba(0,255,120,.38);
  background:
    linear-gradient(135deg, rgba(0,255,120,.16) 0%, rgba(0,255,120,.06) 22%, rgba(4,18,14,.92) 100%);
  box-shadow:
    inset 0 0 0 1px rgba(0,255,120,.06),
    inset 0 0 28px rgba(0,255,120,.08),
    0 0 14px rgba(0,255,120,.06);
}

.kpi-card.kpi-green .kpi-label{
  color:#00ff7a;
  text-shadow: 0 0 6px rgba(0,255,120,.22);
}

.kpi-card.kpi-green .kpi-main,
.kpi-card.kpi-green .kpi-value,
.kpi-card.kpi-green .kpi-unit{
  color:#ecfff4;
}

.kpi-card.kpi-red{
  border: 1px solid rgba(255,77,77,.38);
  background:
    linear-gradient(135deg, rgba(255,77,77,.16) 0%, rgba(255,77,77,.06) 22%, rgba(20,8,8,.92) 100%);
  box-shadow:
    inset 0 0 0 1px rgba(255,77,77,.06),
    inset 0 0 28px rgba(255,77,77,.08),
    0 0 14px rgba(255,77,77,.06);
}

.kpi-card.kpi-grey{
  border: 1px solid rgba(132, 128, 128, 0.38);
  background:
    linear-gradient(135deg, rgba(132, 128, 128, 0.38) 0%, rgba(132, 128, 128, 0.38) 22%, rgba(20,8,8,.92) 100%);
  box-shadow:
    inset 0 0 0 1px rgba(132, 128, 128, 0.38),
    inset 0 0 28px rgba(132, 128, 128, 0.38),
    0 0 14px rgba(132, 128, 128, 0.38);
}

.kpi-card.kpi-red .kpi-label{
  color:#ff5c5c;
  text-shadow: 0 0 6px rgba(255,92,92,.22);
}

.kpi-card.kpi-red .kpi-main,
.kpi-card.kpi-red .kpi-value,
.kpi-card.kpi-red .kpi-unit{
  color:#fff0f0;
}

.mini-trend{
  margin-top: 10px;
  padding: 10px;
  border: 1px solid rgba(20,45,85,0.9);
  border-radius: 12px;
  background: rgba(6,14,26,0.35);
}
}
#batchNo, #poNo{
  font-size: 16px;
  letter-spacing: 0.4px;
  line-height: 1.25;
}


.mini-trend{ margin-top: 10px; padding-top: 10px; border-top: 1px dashed rgba(255,255,255,0.12); }
.mini-title{
  display:flex;
  justify-content:space-between;
  align-items:center;
  font-size: 13px;
  font-weight: 1000;
  letter-spacing: 1.1px;
  text-transform: uppercase;
  color:#eaf3ff;
  margin-bottom: 10px;
}

.mini-last{
  font-size: 13px;
  font-weight: 1000;
  color: rgba(235,245,255,0.95);
  text-transform:none;
}
.mini-chart{
  height: 260px;
  border-radius: 14px;
  border: 1px solid rgba(30,60,110,0.85);
  background: rgba(8,16,28,0.94);
}

/* ================= KPI STATUS COLORS ================= */

.val-ok{
  color:#22c55e !important;
  text-shadow:0 0 8px rgba(34,197,94,.25);
  font-weight:900;
}

.val-bad{
  color:#ff5c5c !important;
  text-shadow:0 0 8px rgba(255,92,92,.25);
  font-weight:900;
}

@keyframes kpiBlink{
  0%,100%{ opacity:1; }
  50%{ opacity:0.25; }
}

.blink{
  animation:kpiBlink 0.8s infinite;
}
/* ================== RIGHT: TABLE ================== */
.pcd-table-head{
  font-size:11px;
  opacity:1;
  letter-spacing:1px;
  font-weight:1000;
  text-transform:uppercase;
  background: linear-gradient(180deg, rgba(255,255,255,.06), rgba(255,255,255,.02));
  border-bottom:1px solid rgba(255,255,255,.10);
  position: sticky;
  top: 0;
  z-index: 2;
}

.pcd-table-head > div{
  text-align:center;
  color:#dcecff;
}

.pcd-row{
  display:grid;
  grid-template-columns: 1.25fr .62fr .72fr .65fr .60fr .82fr .82fr .92fr 1.02fr;
  gap:8px;
  align-items:center;
  padding:13px 12px;
  font-size:12.5px;
}

.pcd-row > div{
  min-width:0;
  overflow-wrap:anywhere;
  word-break:break-word;
  line-height:1.25;
}

/* make MAT HR / START / END / DURATION clearer */
.pcd-row > div:nth-child(5),
.pcd-row > div:nth-child(6),
.pcd-row > div:nth-child(7),
.pcd-row > div:nth-child(8){
  font-weight:1000;
  color:#ffffff;
  opacity:1;
}

/* start & end date/time clearer */
.pcd-row > div:nth-child(6),
.pcd-row > div:nth-child(7){
  line-height:1.35;
  font-size:12px;
  color:#eaf3ff;
}


.pcd-row > div:nth-child(5){
  font-size:13px;
  color:#ffffff;
}

/* duration stay in one line */
.pcd-row > div:nth-child(8){
  white-space:nowrap;
  font-size:12px;
  color:#ffffff;
}

.pcd-item{
  min-height:88px;
  border-bottom:1px solid rgba(255,255,255,.06);
  background: rgba(255,255,255,.01);
  position:relative;
}

.pcd-item:last-child{ border-bottom:0; }

.pcd-item::before{
  content:"";
  position:absolute;
  left:0; top:0; bottom:0;
  width:4px;
  background: rgba(88,166,255,.85);
}

.pcd-strong{
  font-weight:1000;
  color:#ffffff;
  font-size:12px;
  letter-spacing:.2px;
}

.pcd-dim{
  opacity:.92;
  color:#eaf3ff;
  font-size:12px;
  text-align:center;
}

.pcd-chipval{
  display:inline-flex;
  align-items:center;
  justify-content:center;
  padding:6px 9px;
  min-width:48px;
  border-radius:999px;
  font-weight:1000;
  font-size:11.5px;
  color:#ffffff;
  background: rgba(88,166,255,.16);
  border:1px solid rgba(88,166,255,.28);
  box-shadow: inset 0 0 10px rgba(88,166,255,.08);
}

.pcd-chipval.ph{
  background: rgba(125,196,255,.12);
  border-color: rgba(125,196,255,.25);
}

.pcd-state-btn{
  cursor:pointer;
  display:inline-flex;
  align-items:center;
  justify-content:center;
  min-width:96px;
  padding:7px 10px;
  border-radius:999px;
  font-size:11px;
  font-weight:1000;
  letter-spacing:1px;
  white-space:nowrap;
  border:1px solid rgba(255,255,255,.12);
  background: rgba(255,255,255,.06);
}

/* center numeric/date/status columns */
.pcd-row > div:nth-child(2),
.pcd-row > div:nth-child(3),
.pcd-row > div:nth-child(4),
.pcd-row > div:nth-child(5),
.pcd-row > div:nth-child(6),
.pcd-row > div:nth-child(7),
.pcd-row > div:nth-child(8),
.pcd-row > div:nth-child(9){
  text-align:center;
}

.pcd-state-btn.running{
  color: #58a6ff;
  background: rgba(88,166,255,.14);
  border-color: rgba(88,166,255,.32);
  box-shadow: inset 0 0 10px rgba(88,166,255,.08);
}

.pcd-state-btn.completed{
  color: #22c55e;
  background: rgba(34,197,94,.12);
  border-color: rgba(34,197,94,.28);
  box-shadow: inset 0 0 10px rgba(34,197,94,.06);
}
.pcd-state-btn.is-selected{
  box-shadow: 0 0 0 2px rgba(255,255,255,.10), 0 10px 22px rgba(0,0,0,.35);
}

/* ================== Alarm Log ================== */
.log-card{
  height: calc(54% - 10px);
  border-radius:18px;
  border:1px solid rgba(255,255,255,.10);
  background: rgba(255,255,255,.03);
  box-shadow: 0 16px 38px rgba(0,0,0,.55);
  overflow:hidden;
  display:flex;
  flex-direction:column;
}
.log-top{
  display:flex;
  justify-content:space-between;
  align-items:flex-end;
  gap:12px;
}
.log-titlebox{
  border-left:6px solid rgba(88,166,255,.92);
  padding-left:12px;
}
.log-title{ font-weight:1000; letter-spacing:1px; }
.log-sub{ margin-top:3px; font-size:12px; opacity:.78; }

.log-actions{ display:flex; align-items:center; gap:10px; }
.log-badge{
  padding:8px 10px;
  border-radius:12px;
  background: rgba(255,255,255,.08);
  border:1px solid rgba(255,255,255,.12);
  font-size:12px;
  font-weight:900;
  letter-spacing:.6px;
}

.log-search{
  display:flex; align-items:center; gap:8px;
  background: var(--mt-input-bg);
  border:1px solid rgba(255,255,255,.12);
  border-radius:14px;
  padding:10px 12px;
  min-width: 240px;
}
.log-search input{
  width:100%;
  border:0; outline:none;
  background:transparent;
  color:#EAF3FF;
  font-size:13px;
}
.log-ic{ opacity:.8; font-weight:900; }

.log-head{
  display:grid;
  grid-template-columns: 170px 170px 1fr 120px;
  gap:12px;
  padding:14px 16px;
  font-size:12px;
  font-weight:1000;
  letter-spacing:.9px;
  text-transform:uppercase;
  opacity:.85;
  background: rgba(255,255,255,.06);
  border-bottom:1px solid rgba(255,255,255,.10);
}
.log-body{ overflow-y:auto; padding:10px 10px 0; }

.log-row{
  display:grid;
  grid-template-columns: 170px 170px 1fr 120px;
  gap:12px;
  align-items:center;
  padding:14px 14px;
  margin-bottom:10px;
  border-radius:14px;
  background: rgba(0,0,0,.28);
  border:1px solid rgba(255,255,255,.08);
  position:relative;
}
.log-row::before{
  content:"";
  position:absolute;
  left:0; top:0; bottom:0;
  width:6px;
  border-radius:14px 0 0 14px;
  background: rgba(125,196,255,.80);
}
.log-row.sev-high::before{ background: rgba(255,90,90,.90); }
.log-row.sev-med::before{ background: rgba(246,196,69,.95); }
.log-row.sev-low::before{ background: rgba(34,197,94,.90); }
.log-row.sev-info::before{ background: rgba(125,196,255,.85); }

.log-time{
  font-family: ui-monospace, SFMono-Regular, Menlo, Consolas, "Liberation Mono", monospace;
  letter-spacing:.2px;
}
.log-time .dt{ font-size:12px; opacity:.82; }
.log-time .tm{ font-size:18px; font-weight:1000; margin-top:2px; }
.log-code{ font-weight:1000; letter-spacing:.6px; font-size:13px; }
.log-msg .msg-main{ font-size:14px; font-weight:900; }
.log-msg .msg-sub{ margin-top:3px; font-size:12px; opacity:.72; }

.tag{
  display:inline-flex;
  justify-content:center;
  align-items:center;
  padding:8px 12px;
  border-radius:999px;
  font-size:12px;
  font-weight:1000;
  border:1px solid rgba(255,255,255,.10);
  background: rgba(255,255,255,.06);
}

.tag.state.active{
  color:#ff5c5c;
  background: rgba(255,92,92,.14);
  border-color: rgba(255,92,92,.34);
  box-shadow: inset 0 0 10px rgba(255,92,92,.08);
}

.tag.state.clear{
  color:#22c55e;
  background: rgba(34,197,94,.12);
  border-color: rgba(34,197,94,.28);
  box-shadow: inset 0 0 10px rgba(34,197,94,.06);
}
.log-foot{
  margin-top:auto;
  padding:10px 14px;
  display:flex;
  justify-content:space-between;
  align-items:center;
  font-size:12px;
  opacity:.78;
  border-top:1px solid rgba(255,255,255,.08);
  background: rgba(0,0,0,.18);
}

/* ================== RESPONSIVE ================== */
@media (max-width: 1200px){
  .mt-layout{ grid-template-columns: 1fr; }
  .mt-detail-grid{ grid-template-columns: 1fr; height:auto; }
  .pcd-table-wrap{ height: 320px; }
  .log-card{ height: 420px; }
}

/* ACCS HISTORY CARD */
.accs-history-card{
  margin-top:14px;
  border-radius:10px;
  padding:12px;
  background:rgba(10,18,30,0.86);
  border:1px solid rgba(88,166,255,0.14);
}

/* HEADER */
.accs-header{
  font-weight:700;
  font-size:13px;
  letter-spacing:1px;
  margin-bottom:10px;
  color:#b9d7ff;
}

/* LIST */
.accs-history-list{
  display:flex;
  flex-direction:column;
  gap:8px;
}

/* ROW */
.accs-item{
  display:grid;
  grid-template-columns:110px 1fr 90px 110px;
  align-items:center;
  padding:10px 12px;
  border-radius:8px;
  font-size:12px;
  background:rgba(20,34,54,0.65);
  border-left:4px solid transparent;
}

/* COMPLETED */
.accs-item.done{
  border-left:4px solid #22c55e;
}

/* ACTIVE */
.accs-item.running{
  border-left:4px solid #ff5c5c;
  background:rgba(80,20,20,0.30);
}

/* TEXT */
.accs-time{
  font-weight:600;
  color:#dceaff;
}

.accs-process{
  font-weight:700;
  letter-spacing:0.5px;
}

.accs-duration{
  color:#a9c8ef;
}

.accs-status{
  font-weight:700;
  text-align:right;
}

.accs-item.done .accs-status{
  color:#22c55e;
  text-shadow: 0 0 8px rgba(34,197,94,.18);
}

