options.onInit:
// Sets the text from customProperties
const htmlgraphicsText = htmlNode.getElementById('htmlgraphics-text');

if (htmlgraphicsText) {
  htmlgraphicsText.textContent = customProperties.text;

  // Change the text color based on the theme
  if (theme.isDark) {
    htmlgraphicsText.style.color = 'green';
  } else {
    htmlgraphicsText.style.color = 'red';
  }
}

options.onRender:
try {
  const root = htmlNode;
  const seriesList = data?.series || [];

  // ---------- render-safe defer ----------
  const renderKey = Date.now() + "_" + Math.random().toString(36).slice(2);
  root.__renderKey = renderKey;

  // ---------- helpers ----------
  const safeNum = (v, d = NaN) => {
    const n = Number(v);
    return Number.isFinite(n) ? n : d;
  };

  const safeStr = (v, d = "--") => {
    if (v === null || v === undefined) return d;
    const s = String(v).trim();
    return s ? s : d;
  };

  const setText = (sel, val) => {
    const el = root.querySelector(sel);
    if (el) el.textContent = val;
  };

  function clearChart(chartSelector, lastSelector) {
    const chart = root.querySelector(chartSelector);
    if (chart) chart.innerHTML = "";
    if (lastSelector) setText(lastSelector, "--");
  }

  function normalizeSeriesData(times, values, lo, hi) {
    const N = Math.min(times.length, values.length, lo.length, hi.length);
    const outT = [];
    const outV = [];
    const outLo = [];
    const outHi = [];

    for (let i = 0; i < N; i++) {
      const t = times[i];
      const v = Number(values[i]);
      const l = Number(lo[i]);
      const h = Number(hi[i]);

      if (!Number.isFinite(new Date(t).getTime())) continue;
      if (!Number.isFinite(v) || !Number.isFinite(l) || !Number.isFinite(h)) continue;

      outT.push(t);
      outV.push(v);
      outLo.push(l);
      outHi.push(h);
    }

    return { times: outT, values: outV, lo: outLo, hi: outHi };
  }

  function filterTrendByTimeWindow(data, startMs, endMs) {
    const s = Number(startMs);
    const e = Number(endMs);

    if (!Number.isFinite(s) || !Number.isFinite(e) || e <= s) {
      return data;
    }

    const out = {
      times: [],
      values: [],
      lo: [],
      hi: []
    };

    const N = Math.min(
      data.times.length,
      data.values.length,
      data.lo.length,
      data.hi.length
    );

    for (let i = 0; i < N; i++) {
      const ts = new Date(data.times[i]).getTime();

      if (!Number.isFinite(ts)) continue;
      if (ts < s || ts > e) continue;

      out.times.push(data.times[i]);
      out.values.push(data.values[i]);
      out.lo.push(data.lo[i]);
      out.hi.push(data.hi[i]);
    }

    return out.times.length ? out : data;
  }

  function getTankFromUrl() {
    try {
      const params = new URLSearchParams(window.location.search);
      const tankNo = params.get("var-tankNo") || "";
      const tankSuffix = params.get("var-tankSuffix") || "";
      return `${tankNo}${tankSuffix}`;
    } catch (e) {
      return "";
    }
  }

  const defer = (fn) => {
    const myKey = renderKey;
    setTimeout(() => {
      if (root.__renderKey !== myKey) return;
      fn();
    }, 60);
  };

  const getSeries = (refId) =>
    seriesList.find((s) => String(s.refId).toUpperCase() === String(refId).toUpperCase());

  const getSeriesListByRefId = (refId) =>
    seriesList.filter((s) => String(s.refId).toUpperCase() === String(refId).toUpperCase());

  const getFieldFromSeries = (series, name) => {
    if (!series) return null;
    return (series.fields || []).find(
      (x) => String(x.name).toLowerCase() === String(name).toLowerCase()
    ) || null;
  };

  const getArrayFromField = (field) => {
    if (!field) return [];
    if (field.values?.toArray) return field.values.toArray();
    if (field.values?.buffer) return Array.from(field.values.buffer);
    if (Array.isArray(field.values)) return field.values;
    if (field.values?.get) {
      const arr = [];
      const len = field.values.length ?? 0;
      for (let i = 0; i < len; i++) arr.push(field.values.get(i));
      return arr;
    }
    return [];
  };

  const getFirst = (series, fieldName, fallback) => {
    const f = getFieldFromSeries(series, fieldName);
    if (!f) return fallback;
    const v = f.values?.get ? f.values.get(0) : (f.values?.[0] ?? fallback);
    return v ?? fallback;
  };

  const getLabelValue = (series, key, fallback = "--") => {
    if (!series?.fields) return fallback;

    const fld = (series.fields || []).find(
      (f) => String(f.name).toLowerCase() === String(key).toLowerCase()
    );
    if (fld) {
      const v = fld.values?.get ? fld.values.get(0) : (fld.values?.[0] ?? fallback);
      if (v !== undefined && v !== null && String(v).trim() !== "") return v;
    }

    for (const f of series.fields || []) {
      if (f.labels) {
        for (const [k, v] of Object.entries(f.labels)) {
          if (String(k).toLowerCase() === String(key).toLowerCase()) {
            if (v !== undefined && v !== null && String(v).trim() !== "") return v;
          }
        }
      }
    }

    if (series.name && typeof series.name === "string") {
      const m = series.name.match(new RegExp(`${key}=([^,} ]+)`, "i"));
      if (m && m[1]) return m[1];
    }

    return fallback;
  };

  const pickTimeField = (series) => {
    if (!series?.fields) return null;

    let f = series.fields.find((x) => String(x.name).toLowerCase() === "time");
    if (f) return f;

    f = series.fields.find((x) => x.type === "time");
    if (f) return f;

    return (
      series.fields.find((x) => {
        const arr = getArrayFromField(x).slice(0, 3);
        return arr.some((v) => !isNaN(new Date(v).getTime()));
      }) || null
    );
  };

  const pickValueField = (series, preferredNames = []) => {
    if (!series?.fields) return null;

    const prefs = preferredNames.map((s) => String(s).toLowerCase());

    for (const nm of prefs) {
      const f = series.fields.find((x) => String(x.name).toLowerCase() === nm);
      if (f) return f;
    }

    const common = ["_value", "value", "val"];
    for (const nm of common) {
      const f = series.fields.find((x) => String(x.name).toLowerCase() === nm);
      if (f) return f;
    }

    return (
      series.fields.find((x) => {
        if (x.type === "time") return false;
        const arr = getArrayFromField(x).slice(0, 10).map(Number);
        return arr.filter(Number.isFinite).length >= 1;
      }) || null
    );
  };

  function fmtHHMM(v) {
    const d = new Date(v);
    if (isNaN(d.getTime())) return "--";
    return d.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
  }

  function getBatchTrendRows(seriesInput, batchNo, valueField, minField, maxField) {
    const seriesArr = Array.isArray(seriesInput)
      ? seriesInput
      : (seriesInput ? [seriesInput] : []);

    const batchTarget = String(batchNo || "").trim();

    if (!seriesArr.length || !batchTarget) {
      return { times: [], values: [], lo: [], hi: [] };
    }

    const rowMap = new Map();

    function getOrCreateRow(ts, rawTime) {
      const key = String(ts);
      if (!rowMap.has(key)) {
        rowMap.set(key, {
          ts,
          time: rawTime,
          value: NaN,
          min: NaN,
          max: NaN
        });
      }
      return rowMap.get(key);
    }

    for (const series of seriesArr) {
      if (!series?.fields?.length) continue;

      const timeField = pickTimeField(series);
      const times = getArrayFromField(timeField);

      if (!times.length) continue;

      // Batch can come as normal field OR frame label
      const batchField = getFieldFromSeries(series, "batchNo");
      let batches = getArrayFromField(batchField);

      const frameBatch = safeStr(getLabelValue(series, "batchNo", ""), "");

      if (!batches.length && frameBatch) {
        batches = Array(times.length).fill(frameBatch);
      }

      // Sometimes Grafana puts the batch label on each value field, not frame
      if (!batches.length) {
        const anyFieldWithBatch = (series.fields || []).find(f =>
          f.labels && String(f.labels.batchNo || "").trim()
        );

        const fieldBatch = anyFieldWithBatch?.labels?.batchNo;

        if (fieldBatch) {
          batches = Array(times.length).fill(String(fieldBatch).trim());
        }
      }

      const candidateFields = [
        { name: valueField, role: "value" },
        { name: minField, role: "min" },
        { name: maxField, role: "max" }
      ];

      for (const c of candidateFields) {
        const f = getFieldFromSeries(series, c.name);
        if (!f) continue;

        const vals = getArrayFromField(f);
        const N = Math.min(times.length, vals.length);

        for (let i = 0; i < N; i++) {
          const b = String(batches[i] || frameBatch || f.labels?.batchNo || "").trim();
          if (b !== batchTarget) continue;

          const ts = new Date(times[i]).getTime();
          const val = Number(vals[i]);

          if (!Number.isFinite(ts) || !Number.isFinite(val)) continue;

          const row = getOrCreateRow(ts, times[i]);

          if (c.role === "value") row.value = val;
          if (c.role === "min") row.min = val;
          if (c.role === "max") row.max = val;
        }
      }
    }

    const rows = Array.from(rowMap.values())
      .filter(r => Number.isFinite(r.ts) && Number.isFinite(r.value))
      .sort((a, b) => a.ts - b.ts)
      .map(r => {
        // If min/max missing, use value so graph still renders
        if (!Number.isFinite(r.min)) r.min = r.value;
        if (!Number.isFinite(r.max)) r.max = r.value;
        return r;
      });

    return {
      times: rows.map(r => r.time),
      values: rows.map(r => r.value),
      lo: rows.map(r => r.min),
      hi: rows.map(r => r.max)
    };
  }

  function renderSelectedBatchCharts(batchNo, fallback = {}) {

    const life = getBatchLifecycle(batchNo);
    const axisStartMs = Number(life.startMs);
    const axisEndMs = Number(life.endMs) || Date.now();
    const phData = getBatchTrendRows(
      phBatchSeriesList,
      batchNo,
      "ph_current",
      "ph_min",
      "ph_max"
    );

    if (phData.times.length > 0) {
      defer(() =>
        renderMiniTrendWithAxis({
          el: root.querySelector("#phChart"),
          times: phData.times,
          value: phData.values,
          min: phData.lo,
          max: phData.hi,
          lastEl: root.querySelector("#phLast"),
          unit: "",
          yAxisLabel: "pH",
          labels: { value: "pH", min: "Min", max: "Max" },
          useLimitsAsAxis: false,
          axisStartMs,
          axisEndMs,
        })
      );
    } else if (Number.isFinite(Number(fallback.ph))) {
      // fallback: show completed batch table value as single point
      const ph = Number(fallback.ph);
      const phMin = Number.isFinite(Number(fallback.phMin)) ? Number(fallback.phMin) : ph;
      const phMax = Number.isFinite(Number(fallback.phMax)) ? Number(fallback.phMax) : ph;

      defer(() =>
        renderSinglePoint(
          root.querySelector("#phChart"),
          ph,
          phMin,
          phMax,
          root.querySelector("#phLast"),
          "",
          { value: "pH", min: "Min", max: "Max" },
          Date.now(),
          "pH"
        )
      );
    } else {
      clearChart("#phChart", "#phLast");
    }

    const tscData = getBatchTrendRows(
      tscBatchSeriesList,
      batchNo,
      "tsc_current",
      "tsc_min",
      "tsc_max"
    );

    if (tscData.times.length > 0) {
      defer(() =>
        renderMiniTrendWithAxis({
          el: root.querySelector("#tscChart"),
          times: tscData.times,
          value: tscData.values,
          min: tscData.lo,
          max: tscData.hi,
          lastEl: root.querySelector("#tscLast"),
          unit: "%",
          yAxisLabel: "%",
          labels: { value: "TSC", min: "Min", max: "Max" },
          useLimitsAsAxis: false,
          axisStartMs,
          axisEndMs
        })
      );
    } else if (Number.isFinite(Number(fallback.tsc))) {
      // fallback: show completed batch table value as single point
      const tsc = Number(fallback.tsc);
      const tscMin = Number.isFinite(Number(fallback.tscMin)) ? Number(fallback.tscMin) : tsc;
      const tscMax = Number.isFinite(Number(fallback.tscMax)) ? Number(fallback.tscMax) : tsc;

      defer(() =>
        renderSinglePoint(
          root.querySelector("#tscChart"),
          tsc,
          tscMin,
          tscMax,
          root.querySelector("#tscLast"),
          "%",
          { value: "TSC", min: "Min", max: "Max" },
          Date.now(),
          "%"
        )
      );
    } else {
      clearChart("#tscChart", "#tscLast");
    }
  }

  function getHistoryRows(seriesInput) {
    const seriesArr = Array.isArray(seriesInput)
      ? seriesInput
      : (seriesInput ? [seriesInput] : []);

    const out = [];

    for (const series of seriesArr) {
      if (!series?.fields?.length) continue;

      const timeField = pickTimeField(series);

      const batchField = getFieldFromSeries(series, "batchNo");
      const latexField = getFieldFromSeries(series, "latexType");

      const tscField = getFieldFromSeries(series, "tsc_current");
      const tscMinField = getFieldFromSeries(series, "tsc_min");
      const tscMaxField = getFieldFromSeries(series, "tsc_max");

      const phField = getFieldFromSeries(series, "ph_current");
      const phMinField = getFieldFromSeries(series, "ph_min");
      const phMaxField = getFieldFromSeries(series, "ph_max");
      const sourceTimeField = getFieldFromSeries(series, "source_time");

      const times = getArrayFromField(timeField);
      const sourceTimes = getArrayFromField(sourceTimeField);

      let batches = getArrayFromField(batchField);
      let latexes = getArrayFromField(latexField);

      // IMPORTANT:
      // Query F uses GROUP BY "batchNo", "latexType".
      // Grafana may return these as labels, not normal fields.
      const frameBatch = safeStr(getLabelValue(series, "batchNo", ""), "");
      const frameLatex = safeStr(getLabelValue(series, "latexType", ""), "");

      if (!batches.length && frameBatch) {
        batches = Array(Math.max(times.length, 1)).fill(frameBatch);
      }

      if (!latexes.length && frameLatex) {
        latexes = Array(Math.max(times.length, 1)).fill(frameLatex);
      }

      const tscs = getArrayFromField(tscField).map(Number);
      const tscMins = getArrayFromField(tscMinField).map(Number);
      const tscMaxs = getArrayFromField(tscMaxField).map(Number);

      const phs = getArrayFromField(phField).map(Number);
      const phMins = getArrayFromField(phMinField).map(Number);
      const phMaxs = getArrayFromField(phMaxField).map(Number);

      const N = Math.max(
        times.length,
        batches.length,
        latexes.length,
        tscs.length,
        tscMins.length,
        tscMaxs.length,
        phs.length,
        phMins.length,
        phMaxs.length,
        1
      );

      for (let i = 0; i < N; i++) {
        const batch = safeStr(batches[i] ?? frameBatch, "--");
        if (batch === "--") continue;

        const sourceMs = Number(sourceTimes[i]);
        const queryTimeMs = new Date(times[i] ?? null).getTime();

        const sortTime =
          Number.isFinite(sourceMs) && sourceMs > 0
            ? sourceMs
            : queryTimeMs;

        out.push({
          time: Number.isFinite(sortTime) ? sortTime : (times[i] ?? null),
          source_time: Number.isFinite(sourceMs) ? sourceMs : null,
          batch,
          latexType: safeStr(latexes[i] ?? frameLatex, "--"),

          tsc: safeNum(tscs[i], NaN),
          tscMin: safeNum(tscMins[i], NaN),
          tscMax: safeNum(tscMaxs[i], NaN),

          ph: safeNum(phs[i], NaN),
          phMin: safeNum(phMins[i], NaN),
          phMax: safeNum(phMaxs[i], NaN),
        });
      }
    }

    // Remove duplicate batches, keep first occurrence
    const map = new Map();

    for (const r of out) {
      const key = String(r.batch || "").trim();
      if (!key || key === "--") continue;

      if (!map.has(key)) {
        map.set(key, r);
      }
    }

    return Array.from(map.values());
  }

  function isWithinRange(current, min, max) {
    if (!Number.isFinite(current) || !Number.isFinite(min) || !Number.isFinite(max)) return true;

    const lo = Math.min(min, max);
    const hi = Math.max(min, max);
    const EPS = 1e-6;

    return current >= (lo - EPS) && current <= (hi + EPS);
  }

  function renderSinglePoint(
    el,
    value,
    min,
    max,
    lastEl,
    unit = "",
    labels = { value: "Actual", min: "Min", max: "Max" },
    timeVal = null,
    yAxisLabel = ""
  ) {
    if (!el) return;

    const W = el.clientWidth || 560;
    const H = el.clientHeight || 150;
    if (W < 50 || H < 50) {
      el.innerHTML = "";
      return;
    }

    const padL = 72, padR = 58, padT = 42, padB = 54;
    const innerW = W - padL - padR;
    const innerH = H - padT - padB;

    let yMin = Math.min(value, min, max);
    let yMax = Math.max(value, min, max);

    if (!Number.isFinite(yMin) || !Number.isFinite(yMax)) {
      el.innerHTML = "";
      return;
    }

    if (yMin === yMax) {
      yMin -= 1;
      yMax += 1;
    }

    let range = yMax - yMin;
    const center = (yMax + yMin) / 2;

    let targetRange = 0.02;

    if (labels.value === "TSC") targetRange = 0.08;
    if (labels.value === "Level") targetRange = 340;
    if (labels.value === "Hz") targetRange = 50;

    if (range < targetRange) {
      yMin = center - targetRange / 2;
      yMax = center + targetRange / 2;
    } else {
      const pad = range * 0.05;
      yMin -= pad;
      yMax += pad;
    }


    const y = (val) => padT + (1 - (val - yMin) / (yMax - yMin)) * innerH;

    const x1 = padL;
    const x2 = W - padR;

    if (lastEl) lastEl.textContent = Number.isFinite(value) ? `${value.toFixed(2)}${unit}` : "--";

    const ticks = 4;
    const yTicks = Array.from({ length: ticks + 1 }, (_, k) => yMin + (k / ticks) * (yMax - yMin));

    const timeLabel = (() => {
      const d = timeVal ? new Date(timeVal) : new Date();
      return isNaN(d.getTime())
        ? "--:--"
        : d.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
    })();

    const yCurrent = y(value);
    const yLo = y(min);
    const yHi = y(max);

    const clampY = (yy) => Math.max(padT + 10, Math.min(H - padB - 8, yy));
    const labelX = padL + 10;

    el.innerHTML = `
      <svg width="${W}" height="${H}" viewBox="0 0 ${W} ${H}" xmlns="http://www.w3.org/2000/svg">
        ${yAxisLabel ? `<text class="axis-unit axis-title axis-title-y" x="20" y="26" text-anchor="start">${yAxisLabel}</text>` : ""}
        ${yTicks.map((tv) => {
          const yy = y(tv);
          return `
            <line x1="${padL}" y1="${yy}" x2="${W - padR}" y2="${yy}" stroke="rgba(255,255,255,0.08)" stroke-width="1"/>
            <text x="${padL - 8}" y="${yy + 4}" text-anchor="end" fill="rgba(210,225,245,0.78)" font-size="12" font-weight="900">
              ${tv.toFixed(2)}
            </text>
          `;
        }).join("")}

        <line x1="${padL}" y1="${H - padB}" x2="${W - padR}" y2="${H - padB}" stroke="rgba(255,255,255,0.10)" stroke-width="1"/>

        <text class="axis-tick axis-tick-x" x="${(padL + W - padR) / 2}" y="${H - 30}" text-anchor="middle" fill="rgba(210,225,245,0.78)" font-size="12" font-weight="900">
          ${timeLabel}
        </text>
        <text class="axis-unit axis-title axis-title-x" x="${padL + innerW / 2}" y="${H - 8}" text-anchor="middle">Time</text>

        <line x1="${x1}" y1="${yHi}" x2="${x2}" y2="${yHi}" stroke="rgba(125,196,255,0.82)" stroke-width="1.8" stroke-dasharray="5 4"/>
        <line x1="${x1}" y1="${yLo}" x2="${x2}" y2="${yLo}" stroke="rgba(125,196,255,0.82)" stroke-width="1.8" stroke-dasharray="5 4"/>
        <line x1="${x1}" y1="${yCurrent}" x2="${x2}" y2="${yCurrent}" stroke="rgba(88,166,255,0.95)" stroke-width="3.2"/>

        <circle cx="${W - padR - 18}" cy="${yCurrent}" r="4" fill="rgba(88,166,255,0.95)"/>

        <text x="${W - padR - 24}" y="${yCurrent - 8}" text-anchor="end" fill="rgba(240,247,255,0.96)" font-size="12" font-weight="1000">
          ${Number(value).toFixed(2)}${unit}
        </text>

        <text x="${labelX}" y="${clampY(yCurrent + 2)}" fill="rgba(88,166,255,0.95)" font-size="12" font-weight="1000">${labels.value}</text>
        <text x="${labelX}" y="${clampY(yLo - 4)}" fill="rgba(125,196,255,0.82)" font-size="12" font-weight="1000">${labels.min}</text>
        <text x="${labelX}" y="${clampY(yHi - 6)}" fill="rgba(125,196,255,0.82)" font-size="12" font-weight="1000">${labels.max}</text>
      </svg>
    `;
  }

  function getTrendFromRef(refId, currentField, minField, maxField) {
    const frames = getSeriesListByRefId(refId);

    let timeArr = [];
    let currentArr = [];
    let minArr = [];
    let maxArr = [];

    for (const s of frames) {
      const tf = pickTimeField(s);
      const times = getArrayFromField(tf);

      const cf = getFieldFromSeries(s, currentField);
      const lf = getFieldFromSeries(s, minField);
      const hf = getFieldFromSeries(s, maxField);

      if (cf) {
        timeArr = times;
        currentArr = getArrayFromField(cf);
      }

      if (lf) minArr = getArrayFromField(lf);
      if (hf) maxArr = getArrayFromField(hf);
    }

    return normalizeSeriesData(timeArr, currentArr, minArr, maxArr);
  }

  function renderMiniTrendWithAxis({
      el,
      times = [],
      value = [],
      min = [],
      max = [],
      lastEl,
      unit = "",
      yAxisLabel = "",
      labels = { value: "Actual", min: "Min", max: "Max" },
      useLimitsAsAxis = true,
      axisStartMs = null,
      axisEndMs = null,
    }) {
      if (!el) return;

      let N = Math.min(value.length, min.length, max.length, times.length);

      const rows = times.slice(0, N).map((t, i) => ({
        t: new Date(t).getTime(),
        v: Number(value[i]),
        lo: Number(min[i]),
        hi: Number(max[i])
      }))
      .filter(r => Number.isFinite(r.t) && Number.isFinite(r.v))
      .sort((a, b) => a.t - b.t);

      N = rows.length;

      if (N === 1) {
        return renderSinglePoint(
          el,
          rows[0].v,
          rows[0].lo,
          rows[0].hi,
          lastEl,
          unit,
          labels,
          rows[0].t,
          yAxisLabel
        );
      }

      if (N < 2) {
        el.innerHTML = "";
        return;
      }

      const tArr = rows.map(r => r.t);
      const vArr = rows.map(r => r.v);
      const loArr = rows.map(r => r.lo);
      const hiArr = rows.map(r => r.hi);

      const W = el.clientWidth || 560;
      const H = el.clientHeight || 150;
      if (W < 50 || H < 50) {
        el.innerHTML = "";
        return;
      }

      const padL = 72, padR = 58, padT = 42, padB = 54;
      const innerW = W - padL - padR;
      const innerH = H - padT - padB;

      const loFinite = loArr.filter(Number.isFinite);
      const hiFinite = hiArr.filter(Number.isFinite);
      const vFinite = vArr.filter(Number.isFinite);

      let yMin, yMax;
      if (useLimitsAsAxis && loFinite.length && hiFinite.length) {
        yMin = Math.min(...loFinite, ...vFinite);
        yMax = Math.max(...hiFinite, ...vFinite);
      } else {
        const all = [...vFinite, ...loFinite, ...hiFinite].filter(Number.isFinite);
        if (!all.length) {
          el.innerHTML = "";
          return;
        }
        yMin = Math.min(...all);
        yMax = Math.max(...all);
      }

      if (yMin === yMax) {
        yMin -= 1;
        yMax += 1;
      }

      let range = yMax - yMin;
      const center = (yMax + yMin) / 2;

      let targetRange = 0.02;

      if (labels.value === "TSC") targetRange = 0.08;
      if (labels.value === "Level") targetRange = 340;
      if (labels.value === "Hz") targetRange = 50;

      if (range < targetRange) {
        yMin = center - targetRange / 2;
        yMax = center + targetRange / 2;
      } else {
        const pad = range * 0.05;
        yMin -= pad;
        yMax += pad;
      }

      const dataTMin = tArr[0];
      const dataTMax = tArr[tArr.length - 1];

      const fixedStart = Number(axisStartMs);
      const fixedEnd = Number(axisEndMs);

      const tMin = Number.isFinite(fixedStart) && fixedStart > 0
        ? fixedStart
        : dataTMin;

      const tMax = Number.isFinite(fixedEnd) && fixedEnd > tMin
        ? fixedEnd
        : dataTMax;

      const xTs = (ts) => {
        if (!Number.isFinite(ts) || tMax === tMin) {
          return padL;
        }

        return padL + ((ts - tMin) / (tMax - tMin)) * innerW;
      };

      const x = (i) => xTs(tArr[i]);

      const y = (val) => padT + (1 - (val - yMin) / (yMax - yMin)) * innerH;

      const fmtTime = (t) => {
        const d = new Date(t);
        if (isNaN(d.getTime())) return String(t);
        return d.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
      };

      const buildPath = (arr) => {
        let d = "";
        for (let i = 0; i < N; i++) {
          const vv = Number(arr[i]);
          if (!Number.isFinite(vv)) continue;
          d += (d ? " L " : "M ") + `${x(i).toFixed(2)} ${y(vv).toFixed(2)}`;
        }
        return d;
      };

      const ticks = 4;
      const yTicks = Array.from({ length: ticks + 1 }, (_, k) => yMin + (k / ticks) * (yMax - yMin));
      const xTickTs = [
        tMin,
        tMin + ((tMax - tMin) / 2),
        tMax
      ];

      const lastVal = vArr[N - 1];
      if (lastEl) lastEl.textContent = Number.isFinite(lastVal) ? `${lastVal.toFixed(2)}${unit}` : "--";

      const pathVal = buildPath(vArr);
      const pathMin = buildPath(loArr);
      const pathMax = buildPath(hiArr);

      const li = Math.min(1, N - 1);
      const clampY = (yy) => Math.max(padT + 12, Math.min(H - padB - 10, yy));
      const labelX = padL + 10;

      const yMaxLbl = clampY(y(hiArr[li]) - 6);
      const yMinLbl = clampY(y(loArr[li]) - 4);

      const lx = x(N - 1);
      const ly = y(lastVal);

      const COLOR_ACTUAL = "rgba(88,166,255,0.95)";
      const COLOR_MINMAX = "rgba(125,196,255,0.82)";
      const COLOR_GRID = "rgba(255,255,255,0.08)";
      const COLOR_AXIS = "rgba(255,255,255,0.10)";
      const COLOR_TEXT = "rgba(210,225,245,0.78)";
      const COLOR_LASTTX = "rgba(240,247,255,0.96)";

      el.innerHTML = `
        <svg width="${W}" height="${H}" viewBox="0 0 ${W} ${H}" xmlns="http://www.w3.org/2000/svg">
          ${
            yAxisLabel
              ? `<text class="axis-unit axis-title axis-title-y" x="20" y="26" text-anchor="start">${yAxisLabel}</text>`
              : ""
          }
          ${yTicks.map((tv) => {
            const yy = y(tv);
            return `
              <line x1="${padL}" y1="${yy}" x2="${W - padR}" y2="${yy}" stroke="${COLOR_GRID}" stroke-width="1"/>
              <text class="axis-tick axis-tick-y" x="${padL - 8}" y="${yy + 4}" text-anchor="end" fill="${COLOR_TEXT}" font-size="14" font-weight="1000">
                ${tv.toFixed(2)}
              </text>
            `;
          }).join("")}

          <line x1="${padL}" y1="${H - padB}" x2="${W - padR}" y2="${H - padB}" stroke="${COLOR_AXIS}" stroke-width="1"/>

          ${xTickTs.map((ts) => `
            <text class="axis-tick axis-tick-x" x="${xTs(ts)}" y="${H - 30}" text-anchor="middle" fill="${COLOR_TEXT}" font-size="13" font-weight="1000">
              ${fmtTime(ts)}
            </text>
          `).join("")}
          <text class="axis-unit axis-title axis-title-x" x="${padL + innerW / 2}" y="${H - 8}" text-anchor="middle">Time</text>

          <path d="${pathMin}" fill="none" stroke="${COLOR_MINMAX}" stroke-width="1.7" stroke-dasharray="5 4"></path>
          <path d="${pathMax}" fill="none" stroke="${COLOR_MINMAX}" stroke-width="1.7" stroke-dasharray="5 4"></path>
          <path d="${pathVal}" fill="none" stroke="${COLOR_ACTUAL}" stroke-width="3.2"></path>
          <rect class="hover-capture" x="${padL}" y="${padT}" width="${innerW}" height="${innerH}"
                fill="transparent" pointer-events="all"/>

          <text class="limit-label" x="${labelX}" y="${yMinLbl}" fill="${COLOR_MINMAX}" font-size="12" font-weight="1000">${labels.min}</text>
          <text class="limit-label" x="${labelX}" y="${yMaxLbl}" fill="${COLOR_MINMAX}" font-size="12" font-weight="1000">${labels.max}</text>

          ${
            Number.isFinite(lastVal)
              ? `
            <circle cx="${lx}" cy="${ly}" r="3.3" fill="${COLOR_ACTUAL}"/>
            <text class="chart-value-label" x="${Math.min(lx - 8, W - 8)}" y="${ly - 8}" text-anchor="end" fill="${COLOR_LASTTX}" font-size="12" font-weight="1000">
              ${lastVal.toFixed(2)}${unit}
            </text>
          `
              : ""
          }

          <line class="hover-line"
                x1="0" y1="${padT}"
                x2="0" y2="${H - padB}"
                stroke="rgba(255,255,255,0.35)"
                stroke-width="1"
                stroke-dasharray="4 4"
                style="display:none"/>

          <circle class="hover-dot"
                  cx="0"
                  cy="0"
                  r="4"
                  fill="${COLOR_ACTUAL}"
                  stroke="#fff"
                  stroke-width="1.5"
                  style="display:none"/>

          <g class="hover-tip" style="display:none">
            <filter id="tooltipShadow" x="-20%" y="-20%" width="140%" height="140%">
              <feDropShadow dx="0" dy="3" stdDeviation="4" flood-color="#000000" flood-opacity="0.75"/>
            </filter>

            <rect width="230"
            height="104"
            rx="12"
            fill="rgba(8,18,34,0.98)"
            stroke="rgba(88,166,255,0.95)"
            stroke-width="1.2"
            filter="url(#tooltipShadow)"/>

      <rect width="230"
            height="38"
            rx="12"
            fill="rgba(25,85,150,0.88)"/>

            <text class="hover-time"
                  x="12"
                  y="17"
                  fill="#ffffff"
                  font-size="14"
                  font-weight="1000"></text>

            <text class="hover-date"
                  x="12"
                  y="34"
                  fill="#ffffff"
                  font-size="12"
                  font-weight="900"></text>

            <circle cx="15" cy="60" r="5" fill="${COLOR_ACTUAL}"/>

            <text class="hover-val"
                  x="28"
                  y="65"
                  fill="#ffffff"
                  font-size="16"
                  font-weight="1000"></text>

            <text class="hover-range"
                  x="12"
                  y="88"
                  fill="#bfe2ff"
                  font-size="13"
                  font-weight="900"></text>
          </g>
        </svg>
      `;

      const svg = el.querySelector("svg");

      if (svg) {
        const hoverLine = svg.querySelector(".hover-line");
        const hoverDot = svg.querySelector(".hover-dot");
        const hoverTip = svg.querySelector(".hover-tip");
        const hoverTime = svg.querySelector(".hover-time");
        const hoverDate = svg.querySelector(".hover-date");
        const hoverVal = svg.querySelector(".hover-val");
        const hoverRange = svg.querySelector(".hover-range");

        svg.addEventListener("mousemove", (e) => {
          const rect = svg.getBoundingClientRect();
          const mx = ((e.clientX - rect.left) / rect.width) * W;

          let idx = 0;
          let bestDist = Infinity;

          for (let i = 0; i < N; i++) {
            const px = x(i);
            const dist = Math.abs(px - mx);

            if (dist < bestDist) {
              bestDist = dist;
              idx = i;
            }
          }

          idx = Math.max(0, Math.min(N - 1, idx));

          const px = x(idx);
          const py = y(vArr[idx]);

          hoverLine.setAttribute("x1", px);
          hoverLine.setAttribute("x2", px);
          hoverLine.style.display = "";

          hoverDot.setAttribute("cx", px);
          hoverDot.setAttribute("cy", py);
          hoverDot.style.display = "";

          let tipX = px + 10;
          let tipY = py - 104;

          const TIP_W = 230;
          const TIP_H = 104;

          if (tipX + TIP_W > W - 5) {
            tipX = px - TIP_W - 10;
          }

          if (tipY < padT + 5) {
            tipY = py + 14;
          }

          if (tipY + TIP_H > H - padB) {
            tipY = H - padB - TIP_H - 5;
          }

          hoverTip.setAttribute(
            "transform",
            `translate(${tipX},${tipY})`
          );

          hoverTip.style.display = "";

          hoverTime.textContent = fmtTime(tArr[idx]);

          const dt = new Date(tArr[idx]);
          hoverDate.textContent = dt.toLocaleDateString("en-GB", {
            day: "2-digit",
            month: "short",
            year: "numeric"
          });

          hoverVal.textContent = `${vArr[idx].toFixed(2)}${unit}`;

          hoverRange.textContent =
            `Min ${loArr[idx].toFixed(2)}  Max ${hiArr[idx].toFixed(2)}`;
        });

        svg.addEventListener("mouseleave", () => {
          hoverLine.style.display = "none";
          hoverDot.style.display = "none";
          hoverTip.style.display = "none";
        });
      }
    }

    function renderMaturationTrendWithSupply({
      el,
      times = [],
      values = [],
      lastEl,
      supplyStartMs = null,
      supplyStopMs = null
    }) {
      if (!el) return;

      const N = Math.min(times.length, values.length);
      if (N < 2) {
        el.innerHTML = "";
        if (lastEl) lastEl.textContent = "--";
        return;
      }

      const rows = [];
      for (let i = 0; i < N; i++) {
        const ts = new Date(times[i]).getTime();
        const v = Number(values[i]);
        if (!Number.isFinite(ts) || !Number.isFinite(v)) continue;
        rows.push({ ts, v });
      }

      if (rows.length < 2) {
        el.innerHTML = "";
        if (lastEl) lastEl.textContent = "--";
        return;
      }

      const tArr = rows.map(r => r.ts);
      const vArr = rows.map(r => r.v);

      const W = el.clientWidth || 560;
      const H = el.clientHeight || 150;
      if (W < 50 || H < 50) {
        el.innerHTML = "";
        return;
      }

      const padL = 68, padR = 64, padT = 42, padB = 54;
      const innerW = W - padL - padR;
      const innerH = H - padT - padB;

      const xMin = tArr[0];
      const xMax = tArr[tArr.length - 1];

      let yMin = 0;
      let yMax = Math.max(...vArr, 1);
      if (yMax === yMin) yMax += 1;

      const yPad = (yMax - yMin) * 0.08;
      yMax += yPad;

      const x = (ts) => {
        if (xMax === xMin) return padL;
        return padL + ((ts - xMin) / (xMax - xMin)) * innerW;
      };

      const y = (val) => {
        return padT + (1 - (val - yMin) / (yMax - yMin)) * innerH;
      };

      const fmtTime = (t) => {
        const d = new Date(t);
        if (isNaN(d.getTime())) return "--";
        return d.toLocaleTimeString("en-MY", {
          hour: "2-digit",
          minute: "2-digit",
          hour12: true
        });
      };

      const fmtDate = (t) => {
        const d = new Date(t);
        if (isNaN(d.getTime())) return "--";
        return d.toLocaleDateString("en-GB", {
          day: "2-digit",
          month: "short",
          year: "numeric"
        });
      };

      const buildPath = () => {
        let d = "";
        for (let i = 0; i < rows.length; i++) {
          const px = x(rows[i].ts);
          const py = y(rows[i].v);
          d += (d ? " L " : "M ") + `${px.toFixed(2)} ${py.toFixed(2)}`;
        }
        return d;
      };

      const pathVal = buildPath();

      const yTicks = 4;
      const yTickVals = Array.from({ length: yTicks + 1 }, (_, k) =>
        yMin + (k / yTicks) * (yMax - yMin)
      );

      const xTickTs = [
        tArr[0],
        tArr[Math.floor((tArr.length - 1) / 2)],
        tArr[tArr.length - 1]
      ];

      const lastVal = vArr[vArr.length - 1];
      if (lastEl) lastEl.textContent = Number.isFinite(lastVal) ? `${lastVal.toFixed(1)} hr` : "--";

      const COLOR_LINE = "rgba(88,166,255,0.95)";
      const COLOR_GRID = "rgba(255,255,255,0.08)";
      const COLOR_AXIS = "rgba(255,255,255,0.10)";
      const COLOR_TEXT = "rgba(210,225,245,0.78)";
      const COLOR_SHADE = "rgba(42, 255, 138, 0.16)";
      const COLOR_SUPPLY_START = "rgba(255, 211, 61, 0.95)";
      const COLOR_SUPPLY_STOP = "rgba(255, 99, 132, 0.95)";

      const FONT_AXIS = 12;
      const FONT_LABEL = 12;
      const FONT_BOX = 11.5;

      function mhFromStart(ms) {
        const n = Number(ms);
        if (!Number.isFinite(n)) return "--";
        return ((n - xMin) / 1000 / 60 / 60).toFixed(1);
      }

      function clampLabelX(px, boxW) {
        return Math.max(padL + 4, Math.min(W - padR - boxW - 4, px));
      }

      function renderVerticalSupplyMarker(lineX, label, color, side = "right") {
        const offset = side === "right" ? 14 : -10;
        const textX = lineX + offset;
        const textY = H - padB - 8;

        return `
          <line x1="${lineX}" y1="${padT}" x2="${lineX}" y2="${H - padB}"
                stroke="${color}" stroke-width="2.6" stroke-dasharray="5 4"/>

          <text x="${textX}" y="${textY}"
                transform="rotate(-90 ${textX} ${textY})"
                text-anchor="start"
                fill="${color}"
                font-size="12"
                font-weight="1000"
                style="paint-order: stroke; stroke: rgba(8,16,28,0.95); stroke-width: 3px; stroke-linejoin: round;">
            ${label}
          </text>
        `;
      }

      const shadeStart = Number.isFinite(supplyStartMs) ? Math.max(supplyStartMs, xMin) : null;
      const shadeEnd = Number.isFinite(supplyStopMs)
        ? Math.min(supplyStopMs, xMax)
        : (Number.isFinite(supplyStartMs) ? xMax : null);

      const shadeX1 = shadeStart ? x(shadeStart) : null;
      const shadeX2 = shadeEnd ? x(shadeEnd) : null;

      el.innerHTML = `
        <svg width="${W}" height="${H}" viewBox="0 0 ${W} ${H}" xmlns="http://www.w3.org/2000/svg">

          <text class="axis-unit axis-title axis-title-y" x="20" y="26" text-anchor="start">hr</text>

          ${yTickVals.map((tv) => {
            const yy = y(tv);
            return `
              <line x1="${padL}" y1="${yy}" x2="${W - padR}" y2="${yy}" stroke="${COLOR_GRID}" stroke-width="1"/>
              <text class="axis-tick axis-tick-y" x="${padL - 8}" y="${yy + 4}" text-anchor="end" fill="${COLOR_TEXT}" font-size="${FONT_AXIS}" font-weight="900">
                ${tv.toFixed(1)}
              </text>
            `;
          }).join("")}

          <line x1="${padL}" y1="${H - padB}" x2="${W - padR}" y2="${H - padB}" stroke="${COLOR_AXIS}" stroke-width="1"/>

          ${xTickTs.map((ts) => `
            <text class="axis-tick axis-tick-x" x="${x(ts)}" y="${H - 30}" text-anchor="middle" fill="${COLOR_TEXT}" font-size="${FONT_AXIS}" font-weight="900">
              ${fmtTime(ts)}
            </text>
          `).join("")}
          <text class="axis-unit axis-title axis-title-x" x="${padL + innerW / 2}" y="${H - 8}" text-anchor="middle">Time</text>

          ${
            shadeX1 !== null && shadeX2 !== null && shadeX2 > shadeX1
              ? `<rect x="${shadeX1}" y="${padT}" width="${shadeX2 - shadeX1}" height="${innerH}" fill="${COLOR_SHADE}" rx="4"/>`
              : ""
          }

          <path d="${pathVal}" fill="none" stroke="${COLOR_LINE}" stroke-width="3.2"></path>

         ${
          Number.isFinite(supplyStartMs)
            ? (() => {
                const lineX = x(supplyStartMs);
                const mh = mhFromStart(supplyStartMs);

                return renderVerticalSupplyMarker(
                  lineX,
                  `START MH ${mh}`,
                  COLOR_SUPPLY_START,
                  "left"
                );
              })()
            : ""
         }


          ${
            Number.isFinite(supplyStopMs)
              ? (() => {
                  const lineX = x(supplyStopMs);
                  const mh = mhFromStart(supplyStopMs);

                  return renderVerticalSupplyMarker(
                    lineX,
                    `STOP MH ${mh}`,
                    COLOR_SUPPLY_STOP,
                    "right"
                  );
                })()
              : ""
          }

          <line class="hover-line"
                x1="0" y1="${padT}"
                x2="0" y2="${H - padB}"
                stroke="rgba(255,255,255,0.35)"
                stroke-width="1"
                stroke-dasharray="4 4"
                style="display:none"/>

          <circle class="hover-dot"
                  cx="0"
                  cy="0"
                  r="4"
                  fill="${COLOR_LINE}"
                  stroke="#fff"
                  stroke-width="1.5"
                  style="display:none"/>

          <g class="hover-tip" style="display:none">
            <filter id="tooltipShadowMat" x="-20%" y="-20%" width="140%" height="140%">
              <feDropShadow dx="0" dy="3" stdDeviation="4" flood-color="#000000" flood-opacity="0.75"/>
            </filter>

            <rect width="240" height="110" rx="12" fill="rgba(8,18,34,0.98)"
                  stroke="rgba(88,166,255,0.95)" stroke-width="1.2" filter="url(#tooltipShadowMat)"/>
            <rect width="240" height="40" rx="12" fill="rgba(25,85,150,0.88)"/>

            <text class="hover-time" x="12" y="17" fill="#ffffff" font-size="14" font-weight="1000"></text>
            <text class="hover-date" x="12" y="34" fill="#ffffff" font-size="14" font-weight="1000"></text>
            <text class="hover-val" x="12" y="65" fill="#ffffff" font-size="16" font-weight="1000"></text>
            <text class="hover-state" x="12" y="90" fill="#bfe2ff" font-size="13" font-weight="900"></text>
          </g>
        </svg>
      `;

      const svg = el.querySelector("svg");
      if (!svg) return;

      const hoverLine = svg.querySelector(".hover-line");
      const hoverDot = svg.querySelector(".hover-dot");
      const hoverTip = svg.querySelector(".hover-tip");
      const hoverTime = svg.querySelector(".hover-time");
      const hoverDate = svg.querySelector(".hover-date");
      const hoverVal = svg.querySelector(".hover-val");
      const hoverState = svg.querySelector(".hover-state");

      svg.addEventListener("mousemove", (e) => {
        const rect = svg.getBoundingClientRect();
        const mx = ((e.clientX - rect.left) / rect.width) * W;

        let idx = 0;
        let bestDist = Infinity;

        for (let i = 0; i < rows.length; i++) {
          const px = x(rows[i].ts);
          const d = Math.abs(px - mx);
          if (d < bestDist) {
            bestDist = d;
            idx = i;
          }
        }

        const px = x(rows[idx].ts);
        const py = y(rows[idx].v);

        hoverLine.setAttribute("x1", px);
        hoverLine.setAttribute("x2", px);
        hoverLine.style.display = "";

        hoverDot.setAttribute("cx", px);
        hoverDot.setAttribute("cy", py);
        hoverDot.style.display = "";

        let tipX = px + 10;
        let tipY = py - 84;
        const TIP_W = 240;
        const TIP_H = 110;

        if (tipX + TIP_W > W - 5) tipX = px - TIP_W - 10;
        if (tipY < padT + 5) tipY = py + 14;
        if (tipY + TIP_H > H - padB) tipY = H - padB - TIP_H - 5;

        hoverTip.setAttribute("transform", `translate(${tipX},${tipY})`);
        hoverTip.style.display = "";

        const ts = rows[idx].ts;
        hoverTime.textContent = fmtTime(ts);
        hoverDate.textContent = fmtDate(ts);
        hoverVal.textContent = `${rows[idx].v.toFixed(1)} hr`;

        let state = "Before Supply";
        if (Number.isFinite(supplyStartMs) && ts >= supplyStartMs) state = "During Supply";
        if (Number.isFinite(supplyStopMs) && ts > supplyStopMs) state = "After Supply";
        if (Number.isFinite(supplyStartMs) && Math.abs(ts - supplyStartMs) < 60000) state = "Start Supply";
        if (Number.isFinite(supplyStopMs) && Math.abs(ts - supplyStopMs) < 60000) state = "Stop Supply";

        hoverState.textContent = state;
      });

      svg.addEventListener("mouseleave", () => {
        hoverLine.style.display = "none";
        hoverDot.style.display = "none";
        hoverTip.style.display = "none";
      });
    }

  function getNewestHistoryRow(rows) {
