    const supplyStartMs = getBatchSupplyStartMs(batch);
    const supplyStopMs = getLevelZeroStopTimeAfter(supplyStartMs);
    const nowMs = Date.now();

    const isDuringSupply =
      Number.isFinite(Number(supplyStartMs)) &&
      nowMs >= Number(supplyStartMs) &&
      (
        !Number.isFinite(Number(supplyStopMs)) ||
        nowMs <= Number(supplyStopMs)
      );


    if (isDuringSupply && (n < 40 || n > 90)) {
