    const rows = [];

    for (let i = 0; i < N; i++) {
      const ts = new Date(times[i]).getTime();
      const lvl = Number(levels[i]);

      if (!Number.isFinite(ts) || !Number.isFinite(lvl)) continue;

      rows.push({
        ts,
        time: times[i],
        level: lvl
      });
    }

    rows.sort((a, b) => a.ts - b.ts);
    return rows;
  }

  function renderLevelTrendByBatch(batchNo) {
    const dashboardBatch = safeStr(batchNo, "")
      .replace("NO BATCH", "")
      .replace("--", "")
      .trim();

    if (!dashboardBatch) {
      clearChart("#levelChart", "#levelLast");
      return;
    }



    const life = getBatchLifecycle(dashboardBatch);

    const startMs = Number(life.startMs);
    const endMs = Number(life.endMs);

    if (!Number.isFinite(startMs) || startMs <= 0) {
      clearChart("#levelChart", "#levelLast");
      return;
    }

    const currentLevel = getCurrentTankLevel();

    const isRunning =
      String(life.status || "").toUpperCase() === "RUNNING" &&
