      currentLevel > 1;

    const allRows = getAllLevelRows();

    const latestLevelTs = allRows.length
      ? allRows[allRows.length - 1].ts
      : Date.now();

    const finalEndMs =
      Number.isFinite(endMs) && endMs > startMs
        ? endMs
        : latestLevelTs;

    const levelRows = allRows
      .filter(r => r.ts >= startMs && r.ts <= finalEndMs);

    if (!levelRows.length) {
      clearChart("#levelChart", "#levelLast");
      return;
