  }

  function buildAlarmsForSnapshot(snap) {
    const t = nowTimeParts();
    const out = [];

    const batch = safeStr(snap.batch, "--");
    const latex = safeStr(snap.po, "--");
    const tank = safeStr(snap.tank, currentTank);

    const tsc = safeNum(snap.tsc, NaN);
    const tscMin = safeNum(snap.tscMin, NaN);
    const tscMax = safeNum(snap.tscMax, NaN);

    const ph = safeNum(snap.ph, NaN);
    const phMin = safeNum(snap.phMin, NaN);
    const phMax = safeNum(snap.phMax, NaN);

    const hz = safeNum(snap.hz, NaN);
    const mat = safeNum(snap.mat, NaN);
    const level = safeNum(snap.level, NaN);

    if (Number.isFinite(tsc) && Number.isFinite(tscMin) && Number.isFinite(tscMax) && !isWithinRange(tsc, tscMin, tscMax)) {
      out.push({
        dt: t.dt,
        tm: t.tm,
        code: "TSC-OOR",
        msg: "TSC out of range",
        status: "ACTIVE",
        severity: "CRITICAL"
      });
    }

    if (Number.isFinite(ph) && Number.isFinite(phMin) && Number.isFinite(phMax) && !isWithinRange(ph, phMin, phMax)) {
      out.push({
        dt: t.dt,
        tm: t.tm,
        code: "PH-OOR",
        msg: "pH out of range",
        status: "ACTIVE",
        severity: "CRITICAL"
      });
    }

    //if (Number.isFinite(hz) && hz <= 0) {
      //out.push({
        //dt: t.dt,
        //tm: t.tm,
        //code: "STIRRER-STOP",
        //msg: "Stirrer stopped",
        //status: "ACTIVE",
        //severity: "CRITICAL"
     // });
  //  }

    //if (Number.isFinite(mat) && mat < 28) {
     //out.push({
      //  dt: t.dt,
       //tm: t.tm,
        //code: "MAT-LOW",
        //msg: "Maturation hour below target",
        //status: "ACTIVE",
        //severity: "CRITICAL"
     // });
   // }

    if (Number.isFinite(level) && level < 100) {
      out.push({
        dt: t.dt,
        tm: t.tm,
