  function setSelected(btn) {
    root.querySelectorAll(".pcd-state-btn").forEach((b) => b.classList.remove("is-selected"));
    if (btn) btn.classList.add("is-selected");
  }

  function fmtTableDateTime(v) {
    const n = Number(v);
    const d = Number.isFinite(n) ? new Date(n) : new Date(v);

    if (isNaN(d.getTime())) return "--";

    const date = d.toLocaleDateString("en-GB", {
      day: "2-digit",
      month: "short"
    });

    const time = d.toLocaleTimeString("en-MY", {
      hour: "2-digit",
      minute: "2-digit",
      hour12: true
    });

    return `${date}<br>${time}`;
  }

  function fmtDurationFromMs(startMs, endMs) {
    const s = Number(startMs);
    const e = Number(endMs);

    if (!Number.isFinite(s) || !Number.isFinite(e) || e <= s) return "--";

    const totalMin = (e - s) / 1000 / 60;
    const h = Math.floor(totalMin / 60);
    const m = Math.round(totalMin % 60);

    if (h > 0 && m > 0) return `${h}h ${m}m`;
    if (h > 0) return `${h}h`;
    return `${m}m`;
  }

  function getAccsRowByBatch(batchNo) {
    const batch = String(batchNo || "").trim();
    if (!batch) return null;

    const accsRows = getAccsRows(accsSeries);

    return accsRows.find(r =>
      String(r.batchOrderNo || "").trim() === batch
    ) || null;
  }

  function getBatchSupplyStartMs(batchNo) {
  const supplyRow = findSupplyRowByBatch(batchNo);
  const ms = Number(supplyRow?.firstSupplyTimeMs);

  return Number.isFinite(ms) && ms > 0 ? ms : null;
}

  function getLevelZeroStopTimeAfter(startMs) {
    const s = Number(startMs);
    if (!Number.isFinite(s) || s <= 0) return null;

    if (!lvlSeries) return null;

    const timeField = pickTimeField(lvlSeries);
    const levelField = pickValueField(lvlSeries, ["level", "level_cm", "lvl"]);

    const times = getArrayFromField(timeField);
    const levels = getArrayFromField(levelField).map(Number);

    const N = Math.min(times.length, levels.length);
    const rows = [];

    for (let i = 0; i < N; i++) {
      const ts = new Date(times[i]).getTime();
      const lvl = Number(levels[i]);

      if (!Number.isFinite(ts) || !Number.isFinite(lvl)) continue;
      if (ts < s) continue;

      rows.push({ ts, lvl });
    }

    rows.sort((a, b) => a.ts - b.ts);

    // Use <= 1 instead of <= 0 because sensor may not hit exact 0
    const zeroRow = rows.find(r => r.lvl <= 1);

    return zeroRow ? zeroRow.ts : null;
  }

  function getCurrentTankLevel() {
    if (!lvlSeries) return NaN;

    const levelField = pickValueField(lvlSeries, ["level", "level_cm", "lvl"]);
    const levels = getArrayFromField(levelField)
      .map(Number)
      .filter(Number.isFinite);

    if (!levels.length) return NaN;

    // Query E is ORDER BY time ASC, so latest value is the last value
    return levels[levels.length - 1];
  }

  function getBatchLifecycle(batchNo) {
    const batch = String(batchNo || "").trim();
    const accsRow = getAccsRowByBatch(batch);

    const compositeStartMs = Number(accsRow?.compositeStart);

    if (!Number.isFinite(compositeStartMs) || compositeStartMs <= 0) {
      return {
        startMs: null,
        endMs: null,
        matHr: NaN,
        status: null,
        duration: null
      };
    }

    const supplyStartMs = getBatchSupplyStartMs(batch);

    // Very important:
    // End must be detected after supply starts, not after composite starts.
    const stopSearchStartMs = supplyStartMs || compositeStartMs;

    const endMs = getLevelZeroStopTimeAfter(stopSearchStartMs);

    const isLiveBatch =
      String(batch || "").trim() === String(live.batch || "").trim();

    const currentLevel = getCurrentTankLevel();

    // If this is the current live batch and level is still above zero,
    // force RUNNING even if old zero data exists in the graph range.
    const forceRunning =
      isLiveBatch &&
      Number.isFinite(currentLevel) &&
      currentLevel > 1;

    const isCompleted =
      !forceRunning &&
      Number.isFinite(Number(endMs)) &&
      Number(endMs) > stopSearchStartMs;

    const finalEndMs = isCompleted ? Number(endMs) : null;

    const matHr = isCompleted
      ? (finalEndMs - compositeStartMs) / 1000 / 60 / 60
      : (Date.now() - compositeStartMs) / 1000 / 60 / 60;

    return {
      startMs: compositeStartMs,
      endMs: finalEndMs,
      matHr,
      status: isCompleted ? "COMPLETED" : "RUNNING",
      duration: isCompleted ? fmtDurationFromMs(compositeStartMs, finalEndMs) : "Running"
    };
  }

  function createHistoryRow() {
    const row = document.createElement("div");
    row.className = "pcd-row pcd-item";

    row.innerHTML = `
      <div class="pcd-strong">--</div>
      <div class="pcd-strong">--</div>
      <div><span class="pcd-chipval">--</span></div>
