  function renderPreviousLatexTable(historyRows) {
    const wrap = root.querySelector("#pcdTableWrap");
    if (!wrap) return;

    // Remove old dynamic rows, keep header
    wrap.querySelectorAll(".pcd-item").forEach(r => r.remove());

    const rowsIn = Array.isArray(historyRows) ? historyRows : [];

    const liveBatch = String(live.batch || "").trim();

    // Build current live row from Query A
    const liveRow =
      liveBatch && liveBatch !== "--" && liveBatch !== "NO BATCH"
        ? {
            time: live.timeVal || Date.now(),
            batch: live.batch,
            latexType: live.latexType,
            tsc: live.tsc,
            tscMin: live.tscMin,
            tscMax: live.tscMax,
            ph: live.ph,
            phMin: live.phMin,
            phMax: live.phMax,
            forceRunning: true
          }
        : null;

    // Sort history latest first
   let sorted = [...rowsIn].sort((a, b) => {
  const ta = Number(a.source_time || a.time || 0);
  const tb = Number(b.source_time || b.time || 0);

  if (Number.isFinite(ta) && Number.isFinite(tb)) {
    return tb - ta;
  }

  return 0;
});

    // Remove duplicate live batch from history, because we will force live row on top
    if (liveRow) {
      sorted = sorted.filter(r =>
        String(r.batch || "").trim() !== liveBatch
      );

      sorted.unshift(liveRow);
    }

    // Max 5 batches only
    sorted = sorted.slice(0, 5);

    if (!sorted.length) {
      const row = createHistoryRow();
      wrap.appendChild(row);
      return;
    }

    sorted.forEach((item, idx) => {
      const row = createHistoryRow();
      wrap.appendChild(row);

      const batch = String(item.batch || "").trim();
      const liveBatchNow = String(live.batch || "").trim();

      const fallbackState =
        item.forceRunning || batch === liveBatchNow
          ? "RUNNING"
          : "COMPLETED";

      fillHistoryRow(row, item, fallbackState);
    });
  }

  function fillHistoryRow(rowEl, item, fallbackStateText) {
    if (!rowEl) return;

    const cells = rowEl.querySelectorAll(":scope > div");
    const btn = rowEl.querySelector(".pcd-state-btn");

    const batch = item?.batch || "--";
    const latexType = item?.latexType || "--";
    const tsc = Number.isFinite(item?.tsc) ? item.tsc.toFixed(2) + "%" : "--";
    const ph = Number.isFinite(item?.ph) ? item.ph.toFixed(2) : "--";
    const hz = "--";

    const life = getBatchLifecycle(batch);

    const mat = Number.isFinite(life.matHr)
      ? life.matHr.toFixed(1)
      : "--";

    const start = life.startMs
      ? fmtTableDateTime(life.startMs)
      : "--";

    const end = life.endMs
      ? fmtTableDateTime(life.endMs)
      : "--";

    const isCurrentLiveBatch =
      String(batch || "").trim() === String(live.batch || "").trim();

    const currentLevel = getCurrentTankLevel();

    const forceLiveRunning =
      item?.forceRunning === true ||
      (
        isCurrentLiveBatch &&
        Number.isFinite(currentLevel) &&
        currentLevel > 1
      );

    const stateText = forceLiveRunning
      ? "RUNNING"
      : (life.status || fallbackStateText || "COMPLETED");

    const duration = stateText === "RUNNING"
      ? "Running"
      : (life.duration || "--");

    rowEl.setAttribute("data-batch", batch);
    rowEl.setAttribute("data-po", latexType);

    function formatBatchDisplay(batch) {
      const txt = String(batch || "").trim();
      if (!txt || txt === "--") return "--";

      const m = txt.match(/^(HNBON00)(.+)$/);

      if (m) {
        return `
          <span class="batch-prefix">${m[1]}</span>
          <span class="batch-suffix">${m[2]}</span>
        `;
      }

      return `<span class="batch-prefix">${txt}</span>`;
    }

    if (cells[0]) cells[0].innerHTML = formatBatchDisplay(batch);
    if (cells[1]) cells[1].textContent = latexType;
    if (cells[2]) cells[2].innerHTML = `<span class="pcd-chipval">${tsc}</span>`;
    if (cells[3]) cells[3].innerHTML = `<span class="pcd-chipval ph">${ph}</span>`;
    if (cells[4]) cells[4].textContent = mat;
    if (cells[5]) cells[5].innerHTML = start;
    if (cells[6]) cells[6].innerHTML = end;
    if (cells[7]) cells[7].textContent = duration;

    if (btn) {
      btn.textContent = stateText;
      btn.dataset.state = stateText;
      btn.dataset.tank = currentTank;
      btn.dataset.batch = batch;
      btn.dataset.po = latexType;

      btn.dataset.tsc = Number.isFinite(item?.tsc) ? item.tsc : "";
      btn.dataset.tscmin = Number.isFinite(item?.tscMin) ? item.tscMin : "";
      btn.dataset.tscmax = Number.isFinite(item?.tscMax) ? item.tscMax : "";

      btn.dataset.ph = Number.isFinite(item?.ph) ? item.ph : "";
      btn.dataset.phmin = Number.isFinite(item?.phMin) ? item.phMin : "";
      btn.dataset.phmax = Number.isFinite(item?.phMax) ? item.phMax : "";

      btn.dataset.hz = "";
      btn.dataset.mat = Number.isFinite(life.matHr) ? life.matHr : "";

      btn.classList.remove("running", "completed");

      if (stateText === "COMPLETED") {
        btn.classList.add("completed");
      } else {
        btn.classList.add("running");
      }
    }
  }

  renderPreviousLatexTable(preliminaryHistoryRows);
  applyFilter();

  function appendLivePoint(times, values, lo, hi, liveTime, liveValue, liveMin, liveMax) {
    const v = Number(liveValue);
    const mn = Number(liveMin);
    const mx = Number(liveMax);

    if (!Number.isFinite(v)) {
      return { times, values, lo, hi };
    }

    const outTimes = [...times];
    const outValues = [...values];
    const outLo = [...lo];
    const outHi = [...hi];

    const existingMs = outTimes
      .map(t => new Date(t).getTime())
      .filter(Number.isFinite);

    const lastExistingTime = existingMs.length
      ? Math.max(...existingMs)
      : NaN;

    // Force the live KPI point to become the LAST point in the graph
    const liveTimeMs = Number.isFinite(lastExistingTime)
      ? lastExistingTime + 1000
      : Date.now();

    outTimes.push(liveTimeMs);
    outValues.push(v);
    outLo.push(Number.isFinite(mn) ? mn : v);
    outHi.push(Number.isFinite(mx) ? mx : v);

    return {
      times: outTimes,
      values: outValues,
      lo: outLo,
      hi: outHi
    };
  }

  function renderLivePhTscCharts(override = {}) {

    const life = getBatchLifecycle(live.batch);
    const axisStartMs = Number(life.startMs);
    const axisEndMs = Number(life.endMs) || Date.now();
    const usePh = Number.isFinite(Number(override.ph)) ? Number(override.ph) : live.ph;
    const usePhMin = Number.isFinite(Number(override.phMin)) ? Number(override.phMin) : live.phMin;
    const usePhMax = Number.isFinite(Number(override.phMax)) ? Number(override.phMax) : live.phMax;

    const useTsc = Number.isFinite(Number(override.tsc)) ? Number(override.tsc) : live.tsc;
    const useTscMin = Number.isFinite(Number(override.tscMin)) ? Number(override.tscMin) : live.tscMin;
    const useTscMax = Number.isFinite(Number(override.tscMax)) ? Number(override.tscMax) : live.tscMax;

    const phBatchData = getBatchTrendRows(
      phBatchSeriesList,
      live.batch,
      "ph_current",
      "ph_min",
      "ph_max"
    );
    let phTimes = phBatchData.times;
    let phValues = phBatchData.values;
    let phLo = phBatchData.lo;
    let phHi = phBatchData.hi;

    if (!phTimes.length && phSeries) {
      const tf = pickTimeField(phSeries);
      phTimes = getArrayFromField(tf);
      phValues = getArrayFromField(pickValueField(phSeries, ["ph_current", "ph_value", "ph"]));
      phLo = getArrayFromField(pickValueField(phSeries, ["ph_min"]));
      phHi = getArrayFromField(pickValueField(phSeries, ["ph_max"]));
    }

    const phWithLive = appendLivePoint(
      phTimes,
      phValues,
      phLo,
      phHi,
      live.timeVal,
      usePh,
      usePhMin,
      usePhMax
    );

   const phNormRaw = normalizeSeriesData(
      phWithLive.times,
      phWithLive.values,
      phWithLive.lo,
      phWithLive.hi
    );

    const phNorm = filterTrendByTimeWindow(
      phNormRaw,
      axisStartMs,
      axisEndMs
    );

    if (phNorm.times.length > 0) {
      defer(() =>
        renderMiniTrendWithAxis({
          el: root.querySelector("#phChart"),
          times: phNorm.times,
          value: phNorm.values,
          min: phNorm.lo,
          max: phNorm.hi,
          lastEl: root.querySelector("#phLast"),
          unit: "",
          yAxisLabel: "pH",
          labels: { value: "pH", min: "Min", max: "Max" },
          useLimitsAsAxis: false,
          axisStartMs,
          axisEndMs,
        })
      );
    } else {
      clearChart("#phChart", "#phLast");
    }

    const tscBatchData = getBatchTrendRows(
      tscBatchSeriesList,
      live.batch,
      "tsc_current",
      "tsc_min",
      "tsc_max"
    );
    let tscTimes = tscBatchData.times;
    let tscValues = tscBatchData.values;
    let tscLo = tscBatchData.lo;
    let tscHi = tscBatchData.hi;

    if (!tscTimes.length && tscSeries) {
      const tf = pickTimeField(tscSeries);
      tscTimes = getArrayFromField(tf);
      tscValues = getArrayFromField(pickValueField(tscSeries, ["tsc_current", "tsc_value", "tsc"]));
      tscLo = getArrayFromField(pickValueField(tscSeries, ["tsc_min"]));
      tscHi = getArrayFromField(pickValueField(tscSeries, ["tsc_max"]));
    }

    const tscWithLive = appendLivePoint(
      tscTimes,
      tscValues,
      tscLo,
      tscHi,
      live.timeVal,
      useTsc,
      useTscMin,
      useTscMax
    );

    const tscNormRaw = normalizeSeriesData(
      tscWithLive.times,
      tscWithLive.values,
      tscWithLive.lo,
      tscWithLive.hi
    );

    const tscNorm = filterTrendByTimeWindow(
      tscNormRaw,
      axisStartMs,
      axisEndMs
    );

    if (tscNorm.times.length > 0) {
      defer(() =>
        renderMiniTrendWithAxis({
          el: root.querySelector("#tscChart"),
          times: tscNorm.times,
          value: tscNorm.values,
          min: tscNorm.lo,
          max: tscNorm.hi,
          lastEl: root.querySelector("#tscLast"),
          unit: "",
          yAxisLabel: "%",
          labels: { value: "TSC", min: "Min", max: "Max" },
          useLimitsAsAxis: false,
          axisStartMs,
          axisEndMs,
        })
      );
    } else {
      clearChart("#tscChart", "#tscLast");
    }
  }

  function handleStateButtonClick(btn) {
    if (!btn) return;

    setSelected(btn);

    const mode = String(btn.dataset.state || "RUNNING").toUpperCase();
    const currentLevel = getCurrentTankLevel();

    const snap = {
      mode,
      tank: btn.dataset.tank || currentTank,
      batch: btn.dataset.batch || "--",
      po: btn.dataset.po || "--",
      hz: safeNum(btn.dataset.hz, live.hz),
      tsc: safeNum(btn.dataset.tsc, NaN),
      tscMin: safeNum(btn.dataset.tscmin, live.tscMin),
      tscMax: safeNum(btn.dataset.tscmax, live.tscMax),
      ph: safeNum(btn.dataset.ph, NaN),
      phMin: safeNum(btn.dataset.phmin, live.phMin),
      phMax: safeNum(btn.dataset.phmax, live.phMax),
      mat: safeNum(btn.dataset.mat, live.mat),
      level: currentLevel,
    };

    applyKPI({
      batch: snap.batch,
      latexType: snap.po,
      hz: snap.hz,
      tsc: snap.tsc,
      tscMin: snap.tscMin,
      tscMax: snap.tscMax,
      ph: snap.ph,
      phMin: snap.phMin,
      phMax: snap.phMax,
      mat: snap.mat,
    });

    renderAccsHistoryByBatch(snap.batch);
    renderMaturationTrendByBatch(snap.batch);
    renderLevelTrendByBatch(snap.batch);

    const isCurrentLiveBatch =
      String(snap.batch || "").trim() === String(live.batch || "").trim();

    if (mode === "COMPLETED" && !isCurrentLiveBatch) {
      renderSelectedBatchCharts(snap.batch, snap);
    } else {
      renderLivePhTscCharts({
        ph: snap.ph,
        phMin: snap.phMin,
        phMax: snap.phMax,
        tsc: snap.tsc,
        tscMin: snap.tscMin,
        tscMax: snap.tscMax
      });
    }

    const alarmList = buildAlarmsForSnapshot(snap);

    if (alarmSub) alarmSub.textContent = `${mode} • ${snap.batch} • ${snap.po}`;
    if (alarmFootL) alarmFootL.textContent = `Last refresh: ${new Date().toLocaleString()}`;

    renderAlarms(alarmList);
  }

  root.__handleStateButtonClick = handleStateButtonClick;

