  defer(() => {
    const defaultBtn =
      root.querySelector(".pcd-state-btn.running") ||
      root.querySelector(".pcd-state-btn.completed");

    if (
      defaultBtn &&
      typeof root.__handleStateButtonClick === "function" &&
      defaultBtn.dataset.batch &&
      defaultBtn.dataset.batch !== "--"
    ) {
      root.__handleStateButtonClick(defaultBtn);
    } else {
      const currentLevel = safeNum(
        getFirst(lvlSeries, "level", getFirst(lvlSeries, "level_cm", getFirst(lvlSeries, "lvl", NaN))),
        NaN
      );
      const alarmList = buildAlarmsForSnapshot({
        mode: "RUNNING",
        tank: currentTank,
        batch: live.batch,
        po: live.latexType,
        tsc: live.tsc,
        ph: live.ph,
        hz: live.hz,
        mat: live.mat,
        level: currentLevel,
        tscMin: live.tscMin,
        tscMax: live.tscMax,
        phMin: live.phMin,
        phMax: live.phMax,
      });
      renderAlarms(alarmList);
      if (alarmSub) alarmSub.textContent = `RUNNING • ${live.batch} • ${live.latexType}`;
      if (alarmFootL) alarmFootL.textContent = `Last refresh: ${new Date().toLocaleString()}`;
    }
  });

  // ================= ACCS COMPOUNDING HISTORY =================

  function fmtAccsMin(v) {
    const n = Number(v);
    if (!Number.isFinite(n) || n <= 0) return "--";

    return `${n.toFixed(1)} Min`;
  }

  function fmtAccsTotal(v) {
    const n = Number(v);
    if (!Number.isFinite(n) || n <= 0) return "--";

    const h = Math.floor(n / 60);
    const m = n % 60;

    if (h > 0 && m > 0) return `${h}HR ${m.toFixed(1)} Min`;
    if (h > 0) return `${h}HR`;
    return `${m.toFixed(1)} Min`;
  }

  function getLevelZeroStopTime(compositeStartMs) {
      const startMs = Number(compositeStartMs);
      if (!Number.isFinite(startMs) || startMs <= 0) return null;

      if (!lvlSeries) return null;

      const timeField = pickTimeField(lvlSeries);
      const levelField = pickValueField(lvlSeries, ["level", "level_cm", "lvl"]);

      const times = getArrayFromField(timeField);
      const levels = getArrayFromField(levelField).map(Number);

      const N = Math.min(times.length, levels.length);

      const rows = [];

      for (let i = 0; i < N; i++) {
          const ts = new Date(times[i]).getTime();
          const lvl = Number(levels[i]);

          if (!Number.isFinite(ts) || !Number.isFinite(lvl)) continue;
          if (ts < startMs) continue;

          rows.push({
              ts,
              lvl
          });
      }

      rows.sort((a, b) => a.ts - b.ts);

      // Stop maturation when tank level reaches 0 cm
      const zeroRow = rows.find(r => r.lvl <= 0);

      return zeroRow ? zeroRow.ts : null;
  }

  function calcMaturationHourFromComposite(compositeStart) {
      const startMs = Number(compositeStart);
      if (!Number.isFinite(startMs) || startMs <= 0) return NaN;

      const stopMs = getLevelZeroStopTime(startMs);

      // If level reached 0, stop there. Otherwise continue until now.
      const endMs = stopMs || Date.now();

      const diffHr = (endMs - startMs) / 1000 / 60 / 60;

      if (!Number.isFinite(diffHr) || diffHr < 0) return NaN;
      return diffHr;
  }

  function fmtAccsDateTime(v) {
    const n = Number(v);
    if (!Number.isFinite(n) || n <= 0) return "--";

    const d = new Date(n);
    if (!Number.isFinite(d.getTime())) return "--";

    const day = String(d.getDate()).padStart(2, "0");
    const mon = String(d.getMonth() + 1).padStart(2, "0");

    const time = d.toLocaleTimeString("en-MY", {
      hour: "2-digit",
      minute: "2-digit",
      hour12: true
    });

    return `${day}/${mon} ${time}`;
  }

  function getAccsRows(series) {
    if (!series?.fields?.length) return [];

    const fields = [
      "batchOrderNo",
      "currentStage",
      "stabilizerMin",
      "phAdjustmentMin",
      "compositeMin",
      "esdMin",
      "phDilutionMin",
      "waxMin",
      "stabilizerStart",
      "stabilizerEnd",
      "compositeStart",
      "compositeEnd",
      "esdStart",
      "esdEnd",
      "waxStart",
      "waxEnd",
      "updatedAt",
      "tankNo",
      "plant"
    ];

    const dataMap = {};
    fields.forEach((f) => {
      dataMap[f] = getArrayFromField(getFieldFromSeries(series, f));
    });

    const len = Math.max(...Object.values(dataMap).map(a => a.length), 0);
    const rows = [];

    for (let i = 0; i < len; i++) {
      const row = {};
      fields.forEach(f => row[f] = dataMap[f]?.[i]);
      rows.push(row);
    }

    return rows;
  }

  function getSupplyRows(series) {
    if (!series?.fields?.length) return [];

    const fields = [
      "firstSupplyTime",
      "firstSupplyTimeMs",
      "supplyTsc",
      "supplyPh",
      "supplyCoagulum",
      "productionShift",
      "productionDate",
      "productCode",
      "testedByName",
      "lineByPass",
      "plantNo",
      "line",
      "lineNo",
      "supplyTankNo",
      "batchNo"
    ];

    const dataMap = {};
    fields.forEach((f) => {
      dataMap[f] = getArrayFromField(getFieldFromSeries(series, f));
    });

    const len = Math.max(...Object.values(dataMap).map(a => a.length), 0);
    const rows = [];

    for (let i = 0; i < len; i++) {
      const row = {};
      fields.forEach(f => row[f] = dataMap[f]?.[i]);
      rows.push(row);
    }

    return rows;
  }

  function findSupplyRowByBatch(batchNo) {
    if (!batchNo || !supplySeries) return null;

    const rows = getSupplyRows(supplySeries);

    return rows.find(r =>
      String(r.batchNo || "").trim() === String(batchNo || "").trim()
    ) || null;
  }

  function getLevelRowsAfter(startMs) {
    if (!lvlSeries) return [];

    const timeField = pickTimeField(lvlSeries);
    const levelField = pickValueField(lvlSeries, ["level", "level_cm", "lvl"]);

    const times = getArrayFromField(timeField);
    const levels = getArrayFromField(levelField).map(Number);

    const N = Math.min(times.length, levels.length);
    const rows = [];

    for (let i = 0; i < N; i++) {
      const ts = new Date(times[i]).getTime();
      const lvl = Number(levels[i]);

      if (!Number.isFinite(ts) || !Number.isFinite(lvl)) continue;
      if (ts < startMs) continue;

      rows.push({ ts, lvl });
    }

    rows.sort((a, b) => a.ts - b.ts);
    return rows;
  }

  function buildMaturationTrendData(accsRow, supplyRow, batchNo = "") {
    const startMs = Number(accsRow?.compositeStart);
    if (!Number.isFinite(startMs) || startMs <= 0) {
      return null;
    }

    const batch = String(batchNo || "").trim();

    const supplyStartMsRaw = Number(supplyRow?.firstSupplyTimeMs);

    const validSupplyStartMs =
      Number.isFinite(supplyStartMsRaw) && supplyStartMsRaw >= startMs
        ? supplyStartMsRaw
        : null;

    const currentLevel = getCurrentTankLevel();

    const isCurrentLiveBatch =
      batch &&
      String(batch).trim() === String(live.batch || "").trim();

    const forceRunning =
      isCurrentLiveBatch &&
      Number.isFinite(currentLevel) &&
      currentLevel > 1;

    const stopSearchStartMs = validSupplyStartMs || startMs;

    // If current batch is still running, do not stop at old zero point
    const stopMs = forceRunning
      ? null
      : getLevelZeroStopTimeAfter(stopSearchStartMs) || null;

    const endMs = forceRunning
      ? Date.now()
      : (stopMs || Date.now());

    const levelRows = getLevelRowsAfter(startMs).filter(r => r.ts <= endMs);

    const times = [startMs];
    const values = [0];

    for (const r of levelRows) {
      const hr = (r.ts - startMs) / 1000 / 60 / 60;
      if (Number.isFinite(hr) && hr >= 0) {
        times.push(r.ts);
        values.push(hr);
      }
    }

    if (times[times.length - 1] !== endMs) {
      times.push(endMs);
      values.push((endMs - startMs) / 1000 / 60 / 60);
    }

    const supplyStopMs =
      validSupplyStartMs && stopMs && stopMs > validSupplyStartMs
        ? stopMs
        : null;

    return {
      startMs,
      stopMs,
      endMs,
      supplyStartMs: validSupplyStartMs,
      supplyStopMs,
      times,
      values
    };
  }

  function renderMaturationTrendByBatch(batchNo) {
    const dashboardBatch = safeStr(batchNo, "")
      .replace("NO BATCH", "")
      .replace("--", "")
      .trim();

    if (!dashboardBatch) {
      clearChart("#invChart", "#invLast");
      return;
    }

    const accsRows = getAccsRows(accsSeries);
    const accsRow = accsRows.find(r =>
      String(r.batchOrderNo || "").trim() === dashboardBatch
    );

    const supplyRow = findSupplyRowByBatch(dashboardBatch);

    const trendData = buildMaturationTrendData(accsRow, supplyRow, dashboardBatch);

    if (trendData && trendData.times.length >= 2) {
      defer(() =>
        renderMaturationTrendWithSupply({
          el: root.querySelector("#invChart"),
          times: trendData.times,
          values: trendData.values,
          lastEl: root.querySelector("#invLast"),
          supplyStartMs: trendData.supplyStartMs,
          supplyStopMs: trendData.supplyStopMs
        })
      );
    } else {
      clearChart("#invChart", "#invLast");
    }
  }

  function clearAccsHistory() {
    const accsCard = root.querySelector("#accsHistoryCard");
    if (accsCard) accsCard.classList.add("accs-disabled");

    root.querySelectorAll(".accs-item").forEach((item) => {
      item.classList.remove("done", "running");
      item.querySelector(".accs-time").textContent = "--";
      item.querySelector(".accs-duration").textContent = "--";
      item.querySelector(".accs-status").textContent = "--";
    });

    const totalEl = root.querySelector("#accsTotalTime");
    if (totalEl) totalEl.textContent = "--";

    setText("#maturationHour", "--");
    applyMaturationColor(NaN);
  }

  function renderAccsHistoryByBatch(forcedBatch = "") {
    const accsCard = root.querySelector("#accsHistoryCard");
    if (!accsCard) return;

    const dashboardBatch = safeStr(
      forcedBatch || root.querySelector("#batchNo")?.textContent,
      ""
    )
      .replace("NO BATCH", "")
      .replace("--", "")
      .trim();

    if (!dashboardBatch) {
      clearAccsHistory();
      return;
    }

    const rows = getAccsRows(accsSeries);

    const accsRow = rows.find(r =>
      String(r.batchOrderNo || "").trim() === dashboardBatch
    );

    // IMPORTANT: no fallback to rows[0]
    // If batch not found, show blank to avoid wrong ACCS history.
    if (!accsRow) {
      clearAccsHistory();
      return;
    }

    // Maturation hour = from Composite Start until current time
    const life = getBatchLifecycle(dashboardBatch);
    const maturationHr = Number(life.matHr);

    if (Number.isFinite(maturationHr)) {
      setText("#maturationHour", maturationHr.toFixed(1));
      applyMaturationColor(maturationHr, dashboardBatch);
    } else {
      setText("#maturationHour", "--");
      applyMaturationColor(NaN);
    }

    accsCard.classList.remove("accs-disabled");

    const stages = [
    {
      label: "STABILIZER",
      min: "stabilizerMin",
      start: "stabilizerStart",
      end: "stabilizerEnd"
    },
    {
      label: "PH ADJUSTMENT",
      min: "phAdjustmentMin",
      start: "stabilizerEnd",
      end: "compositeStart"
    },
    {
      label: "COMPOSITE",
      min: "compositeMin",
      start: "compositeStart",
      end: "compositeEnd"
    },
    {
      label: "ESD",
      min: "esdMin",
      start: "esdStart",
      end: "esdEnd"
    },
    {
      label: "PH DILUTION",
      min: "phDilutionMin",
      start: "esdEnd",
      end: "waxStart"
    },
    {
      label: "WAX ADDITION",
      min: "waxMin",
      start: "waxStart",
      end: "waxEnd"
    }
  ];

    const items = root.querySelectorAll(".accs-item");
    let totalMin = 0;

    stages.forEach((s, i) => {
      const item = items[i];
      if (!item) return;

      const minVal = Number(accsRow[s.min]);
      const hasDuration = Number.isFinite(minVal) && minVal > 0;

      if (hasDuration) totalMin += minVal;

      item.classList.remove("done", "running");

      const currentStage = String(accsRow.currentStage || "").toUpperCase();

      const isRunning =
        !hasDuration &&
        currentStage &&
        currentStage.includes(s.label.split(" ")[0]);

      if (hasDuration) item.classList.add("done");
      else if (isRunning) item.classList.add("running");

      const startText = fmtAccsDateTime(accsRow[s.start]);
      const endText = fmtAccsDateTime(accsRow[s.end]);

      item.querySelector(".accs-time").textContent = hasDuration
        ? `${startText} → ${endText}`
        : "--";

      item.querySelector(".accs-process").textContent = s.label;

      item.querySelector(".accs-duration").textContent = hasDuration
        ? fmtAccsMin(minVal)
        : "--";

      item.querySelector(".accs-status").textContent = hasDuration
        ? "COMPLETED"
        : isRunning
          ? "RUNNING"
          : "--";
    });

    const totalEl = root.querySelector("#accsTotalTime");
    if (totalEl) totalEl.textContent = fmtAccsTotal(totalMin);
  }

  renderAccsHistoryByBatch();

} catch (e) {
  console.log("MT Dashboard OnRender error:", e);
}
